globalThis.__BQ = {"hayvanHucresi":{"ilkokul":{"kolay":[{"q":"Hayvan hücresinin en dış sınırını oluşturan ve hücreyi çevreleyen yapı nedir?","steps":[{"t":"Dış sınırı bulalım","a":"Hücre zarı","d":"Hayvan hücresinin en dışında ince bir örtü bulunur. Bu örtü hücrenin içini dışarıdan ayırır ve hücreye şeklini verir."},{"t":"Görevini düşünelim","a":"Madde geçişi","d":"Hücre zarı hangi maddelerin içeri gireceğini, hangilerinin dışarı çıkacağını kontrol eder. Böylece hücreyi korur ve düzeni sağlar."}],"ans":"Hücre zarı"},{"q":"Hayvan hücresinde yönetim merkezi olarak çalışan ve genetik bilgiyi taşıyan organel hangisidir?","steps":[{"t":"Yönetim merkezini arayalım","a":"Çekirdek","d":"Hücrenin ortasında genellikle yuvarlak ve koyu görünen büyük bir yapı vardır. Bu yapı hücrenin beyni gibi davranır."},{"t":"İçindekini düşünelim","a":"Kalıtım bilgisi","d":"Çekirdeğin içinde hücrenin özelliklerini belirleyen kalıtım bilgisi saklanır. Çekirdek hücrenin tüm faaliyetlerini yönetir."}],"ans":"Çekirdek"},{"q":"Hayvan hücresinin içini dolduran, jöle kıvamındaki sıvıya ne ad verilir?","steps":[{"t":"İçteki sıvıyı bulalım","a":"Sitoplazma","d":"Hücre zarının içinde her yeri dolduran yumuşak ve sulu bir madde bulunur. Bu maddeye sitoplazma denir."},{"t":"İçinde ne var bakalım","a":"Organeller yüzer","d":"Sitoplazmanın içinde organeller yer alır. Bu sıvı organelleri taşır ve hücre içinde olayların gerçekleşmesini sağlar."}],"ans":"Sitoplazma"},{"q":"Bir hayvan hücresinde hücre duvarı bulunur mu?","steps":[{"t":"Hücre duvarını arayalım","a":"Bulunmaz","d":"Hayvan hücresinin etrafında sadece ince bir hücre zarı vardır. Sert bir hücre duvarı bulunmaz."},{"t":"Kimde olduğunu düşünelim","a":"Bitkide var","d":"Sert hücre duvarı sadece bitki hücrelerinde bulunur. Bu yüzden hayvan hücreleri daha yumuşak ve değişik şekiller alabilir."}],"ans":"Hayır, hayvan hücresinde hücre duvarı bulunmaz"},{"q":"Hayvan hücresi mi yoksa bitki hücresi mi daha çok yuvarlak ve düzensiz bir şekle sahiptir?","steps":[{"t":"Şekli inceleyelim","a":"Hayvan hücresi yuvarlak","d":"Hayvan hücresinin sert bir duvarı olmadığı için kenarları yuvarlak ve düzensiz görünür. Hücre kolayca şeklini değiştirebilir."},{"t":"Bitkiyle karşılaştıralım","a":"Bitki köşeli","d":"Bitki hücresi ise sert duvarı sayesinde köşeli ve düzenli bir kutu gibi görünür. Bu yüzden iki hücre kolayca ayırt edilir."}],"ans":"Hayvan hücresi daha yuvarlak ve düzensizdir"}],"zor":[{"q":"Hayvan hücresinde kloroplast bulunmadığına göre, bu hücre kendi besinini üretebilir mi? Açıklayınız.","steps":[{"t":"Kloroplastı arayalım","a":"Hayvanda yok","d":"Kloroplast besin üretmeyi sağlayan yeşil organeldir. Hayvan hücresinde kloroplast bulunmaz."},{"t":"Sonucu düşünelim","a":"Üretemez","d":"Kloroplast olmadığı için hayvan hücresi kendi besinini yapamaz. Bu yüzden hayvanlar dışarıdan hazır besin almak zorundadır."}],"ans":"Hayır, kloroplast olmadığı için kendi besinini üretemez, dışarıdan hazır besin alır"},{"q":"Bir öğrenci mikroskopta bir hücre gözlemliyor; hücrenin kenarları yumuşak ve yuvarlak, içinde kloroplast yok. Bu hücre hangi canlıya ait olabilir?","steps":[{"t":"İpuçlarını toplayalım","a":"Yuvarlak ve kloroplastsız","d":"Hücrenin kenarları yuvarlak ve yumuşak görünüyor, yani sert duvarı yok. Ayrıca kloroplast bulunmuyor."},{"t":"Hücre türüne karar verelim","a":"Hayvan hücresi","d":"Duvarsız ve kloroplastsız olması hayvan hücresinin özelliğidir. Bu yüzden hücre bir hayvana aittir."}],"ans":"Hayvan hücresine aittir"},{"q":"Hayvan hücresinde çekirdek zarla çevrili olduğuna göre, bu çekirdeğin içindeki bilgi nasıl korunur?","steps":[{"t":"Çekirdek zarını inceleyelim","a":"Koruyucu zar","d":"Çekirdeğin etrafında ince bir çekirdek zarı bulunur. Bu zar çekirdeğin içini sitoplazmadan ayırır."},{"t":"Korumayı düşünelim","a":"Bilgi güvende","d":"Çekirdek zarı sayesinde kalıtım bilgisi dış etkilerden korunur. Böylece hücrenin önemli bilgileri güvenli bir şekilde saklanır."}],"ans":"Çekirdek zarı kalıtım bilgisini çevreleyip dış etkilerden koruyarak güvende tutar"},{"q":"Hayvan hücresinin bir kutuya benzemeyip yumuşak bir top gibi şekil alabilmesinin nedeni nedir?","steps":[{"t":"Eksik yapıyı bulalım","a":"Duvar yok","d":"Hayvan hücresinde sert hücre duvarı bulunmaz. Sadece esnek bir hücre zarı vardır."},{"t":"Sonucu açıklayalım","a":"Esnek şekil","d":"Esnek zar sayesinde hücre şeklini kolayca değiştirebilir. Bu yüzden hayvan hücresi köşeli bir kutu yerine yumuşak bir top gibi görünür."}],"ans":"Sert hücre duvarı olmayıp sadece esnek hücre zarı bulunduğu için şeklini değiştirebilir"},{"q":"Bir hayvan hücresinin yaşaması için neden sürekli dışarıdan besin alması gerekir?","steps":[{"t":"Besin üretimini düşünelim","a":"Kendi üretemez","d":"Hayvan hücresinde besin üreten kloroplast yoktur. Bu yüzden hücre kendi besinini yapamaz."},{"t":"Çözümü bulalım","a":"Dışarıdan alır","d":"Besin üretemediği için hücre yaşamak ve enerji elde etmek için dışarıdan hazır besin almalıdır. Bu besin sayesinde hücre çalışmaya devam eder."}],"ans":"Kendi besinini üretemediği için yaşamını sürdürmek üzere dışarıdan hazır besin almalıdır"}]},"ortaokul":{"kolay":[{"q":"Hayvan hücresinin temel kısımları olan hücre zarı, sitoplazma ve çekirdeğin görevlerini sırasıyla belirtiniz.","steps":[{"t":"Hücre zarını ele alalım","a":"Madde geçişi","d":"Hücre zarı hücrenin dış sınırıdır ve seçici geçirgendir. İhtiyaç duyulan maddelerin girişini, atık maddelerin çıkışını kontrol eder."},{"t":"Sitoplazmayı ele alalım","a":"Ortam ve organeller","d":"Sitoplazma hücre zarı ile çekirdek arasını dolduran sıvıdır. İçinde organeller bulunur ve yaşamsal olaylar burada gerçekleşir."},{"t":"Çekirdeği ele alalım","a":"Yönetim","d":"Çekirdek hücrenin yönetim merkezidir ve kalıtım maddesini taşır. Hücredeki tüm faaliyetleri düzenler ve kontrol eder."}],"ans":"Hücre zarı madde geçişini kontrol eder, sitoplazma ortam ve organel sağlar, çekirdek hücreyi yönetir"},{"q":"Hayvan hücresinde bulunup bitki hücresinde bulunmayan organel sentrozomun temel görevi nedir?","steps":[{"t":"Sentrozomu tanıyalım","a":"Hayvana özgü","d":"Sentrozom çoğunlukla hayvan hücrelerinde bulunan bir organeldir. Çekirdeğin yakınında yer alır."},{"t":"Görevini belirleyelim","a":"Bölünmede iş görür","d":"Sentrozom hücre bölünmesi sırasında iş görür. Bölünme sırasında kalıtım maddesinin doğru şekilde dağıtılmasına yardım eder."}],"ans":"Sentrozom hücre bölünmesinde görev alır"},{"q":"Hayvan hücresinde kofullar bitki hücresine kıyasla nasıldır?","steps":[{"t":"Hayvan kofullarını inceleyelim","a":"Küçük ve çok","d":"Hayvan hücresinde kofullar genellikle küçük ve sayıca fazladır. Bu kofullar geçici olarak bulunabilir."},{"t":"Bitkiyle karşılaştıralım","a":"Bitki büyük tek","d":"Bitki hücresinde ise genellikle tek ve büyük bir merkezi koful bulunur. Yani kofullar konusunda iki hücre belirgin şekilde farklıdır."}],"ans":"Hayvan hücresinde kofullar küçük ve sayıca çoktur"},{"q":"Bir hücrede hücre duvarı ve kloroplast bulunmuyorsa bu hücre hayvan hücresi midir? Gerekçesini açıklayınız.","steps":[{"t":"Eksik yapıları tespit edelim","a":"Duvar ve kloroplast yok","d":"Verilen hücrede hücre duvarı ve kloroplast yoktur. Bu iki yapı bitki hücresine özgüdür."},{"t":"Karar verelim","a":"Hayvan hücresi","d":"Bu yapıların bulunmaması hayvan hücresinin temel özelliğidir. Bu nedenle verilen hücre hayvan hücresidir."}],"ans":"Evet, hücre duvarı ve kloroplast bulunmadığı için hayvan hücresidir"},{"q":"Hayvan hücresinde enerji üretiminden sorumlu olan organel hangisidir?","steps":[{"t":"Enerji organelini arayalım","a":"Mitokondri","d":"Hücrede besinlerin parçalanarak enerjiye dönüştürüldüğü organel mitokondridir. Bu organel hücrenin enerji santrali olarak bilinir."},{"t":"Önemini düşünelim","a":"Yaşam enerjisi","d":"Mitokondri ürettiği enerji ile hücrenin tüm faaliyetlerini destekler. Enerji ihtiyacı fazla olan hücrelerde mitokondri sayısı daha çoktur."}],"ans":"Mitokondri"}],"zor":[{"q":"Kas hücreleri çok fazla enerji harcar. Bu durumun kas hücrelerindeki mitokondri sayısı ile ilişkisini açıklayınız.","steps":[{"t":"Enerji ihtiyacını belirleyelim","a":"Yüksek enerji","d":"Kas hücreleri kasılıp gevşerken sürekli olarak büyük miktarda enerji harcar. Bu yüzden enerji ihtiyaçları diğer hücrelere göre çok yüksektir."},{"t":"Mitokondri görevini hatırlayalım","a":"Enerji üretir","d":"Mitokondri besinleri parçalayarak hücre için enerji üretir. Enerji ihtiyacı arttıkça daha fazla mitokondriye gerek duyulur."},{"t":"İlişkiyi kuralım","a":"Çok mitokondri","d":"Kas hücreleri yüksek enerji gereksinimi nedeniyle bol miktarda mitokondri içerir. Böylece kasların çalışması için yeterli enerji sağlanır."}],"ans":"Kas hücreleri yüksek enerji harcadığı için bol miktarda mitokondri içerir"},{"q":"Hayvan hücresinin sert bir hücre duvarı olmaması ona hangi avantajı sağlar?","steps":[{"t":"Yapısal farkı belirleyelim","a":"Esnek zar","d":"Hayvan hücresinin etrafında sert duvar yerine esnek bir hücre zarı bulunur. Bu zar hücrenin şeklini kolayca değiştirebilmesini sağlar."},{"t":"Avantajı açıklayalım","a":"Hareket ve şekil","d":"Esnek yapı sayesinde bazı hücreler şekil değiştirebilir, hareket edebilir veya yutma yapabilir. Örneğin akyuvarlar şekil değiştirerek mikropları yutar."}],"ans":"Sert duvar olmaması hücreye esneklik, şekil değiştirme ve hareket edebilme avantajı sağlar"},{"q":"Hayvan hücresinde sentrozom bulunurken bitki hücresinde genellikle bulunmaz. Bu durumun hücre bölünmesi açısından önemi nedir?","steps":[{"t":"Sentrozomun yerini belirleyelim","a":"Hayvanda var","d":"Sentrozom çoğunlukla hayvan hücrelerinde çekirdek yakınında bulunur. Bitki hücrelerinde ise genellikle bulunmaz."},{"t":"Görevini hatırlayalım","a":"Bölünmeye yardım","d":"Sentrozom hücre bölünmesi sırasında kalıtım maddesinin yavru hücrelere düzgün dağıtılmasına yardımcı olur. Bölünmenin düzenli ilerlemesini destekler."},{"t":"Önemini açıklayalım","a":"Düzenli dağılım","d":"Hayvan hücreleri sentrozom sayesinde bölünme sırasında kalıtım maddesini düzenli paylaştırır. Bu, yavru hücrelerin eksiksiz bilgi almasını sağlar."}],"ans":"Sentrozom hücre bölünmesinde kalıtım maddesinin yavru hücrelere düzenli dağıtılmasını sağlar"},{"q":"Hücre zarının seçici geçirgen olması bir hayvan hücresi için neden önemlidir?","steps":[{"t":"Seçici geçirgenliği tanımlayalım","a":"Kontrollü geçiş","d":"Seçici geçirgenlik, zarın bazı maddeleri geçirip bazılarını geçirmemesi demektir. Yani zar her maddeye izin vermez."},{"t":"Önemini düşünelim","a":"Denge ve koruma","d":"Bu özellik sayesinde hücre yararlı maddeleri alır, zararlı veya gereksiz maddeleri dışarıda tutar. Böylece hücre içi denge korunur."},{"t":"Sonuca varalım","a":"Sağlıklı hücre","d":"Seçici geçirgenlik hücrenin iç ortamını dengede tutar ve onu zararlı etkilerden korur. Bu da hücrenin sağlıklı çalışmasını sağlar."}],"ans":"Seçici geçirgenlik yararlı maddeleri alıp zararlıları dışarıda tutarak hücre içi dengeyi ve sağlığı korur"},{"q":"Bir hücrenin hem küçük ve çok sayıda kofula sahip olması hem de hücre duvarı bulunmaması neyi gösterir?","steps":[{"t":"Koful özelliğini inceleyelim","a":"Çok ve küçük","d":"Küçük ve sayıca çok koful bulunması hayvan hücrelerinin tipik özelliğidir. Bitki hücresinde ise tek ve büyük bir koful olur."},{"t":"Duvar durumunu inceleyelim","a":"Duvar yok","d":"Hücre duvarının bulunmaması da bitki hücresine ait olmadığını gösterir. Sadece esnek bir zar vardır."},{"t":"Sonuca ulaşalım","a":"Hayvan hücresi","d":"Hem koful özelliği hem de duvar yokluğu birlikte değerlendirildiğinde bu hücrenin hayvan hücresi olduğu anlaşılır. İki özellik de hayvan hücresini işaret eder."}],"ans":"Bu hücrenin bir hayvan hücresi olduğunu gösterir"}]},"lise":{"kolay":[{"q":"Hayvan hücresini prokaryot bir hücreden ayıran en temel yapısal özellik nedir?","steps":[{"t":"Prokaryot yapıyı inceleyelim","a":"Zarsız çekirdek","d":"Prokaryot hücrelerde kalıtım maddesi zarla çevrili bir çekirdek içinde değildir, sitoplazmada serbest bulunur. Ayrıca zarlı organelleri yoktur."},{"t":"Hayvan hücresini inceleyelim","a":"Zarlı çekirdek","d":"Hayvan hücresi ökaryottur ve çekirdeği zarla çevrilidir. Ayrıca mitokondri gibi zarlı organellere sahiptir."},{"t":"Farkı belirleyelim","a":"Çekirdek zarı","d":"En temel ayırt edici özellik, hayvan hücresinde zarla çevrili gerçek bir çekirdeğin bulunmasıdır. Bu, onu ökaryot yapan başlıca özelliktir."}],"ans":"Hayvan hücresinde zarla çevrili gerçek bir çekirdek (ökaryot yapı) bulunması"},{"q":"Hayvan hücresinde ribozomların görevi nedir?","steps":[{"t":"Ribozomu tanıyalım","a":"Zarsız organel","d":"Ribozomlar zarsız küçük organellerdir ve sitoplazmada serbest ya da endoplazmik retikulum üzerinde bulunur. Tüm canlı hücrelerde vardır."},{"t":"Görevini belirleyelim","a":"Protein sentezi","d":"Ribozomlar amino asitleri birleştirerek protein sentezi yapar. Çekirdekten gelen bilgiye göre proteinleri üretir."}],"ans":"Ribozomlar protein sentezini gerçekleştirir"},{"q":"Endoplazmik retikulumun granüllü (tanecikli) ve granülsüz (düz) çeşitlerinin görevleri nelerdir?","steps":[{"t":"Granüllü tipi inceleyelim","a":"Protein taşır","d":"Granüllü endoplazmik retikulumun üzerinde ribozomlar bulunur. Bu yüzden sentezlenen proteinlerin taşınması ve işlenmesinde görev alır."},{"t":"Granülsüz tipi inceleyelim","a":"Lipit sentezi","d":"Granülsüz endoplazmik retikulumda ribozom bulunmaz. Lipit ve karbonhidrat metabolizmasında ve bazı maddelerin zararsız hale getirilmesinde görev yapar."}],"ans":"Granüllü ER protein işleme ve taşımada, granülsüz ER lipit sentezi ve detoksifikasyonda görev alır"},{"q":"Golgi cisimciğinin (golgi aygıtının) hayvan hücresindeki temel görevi nedir?","steps":[{"t":"Golgiyi tanıyalım","a":"Yassı keseler","d":"Golgi cisimciği üst üste dizilmiş yassı keseciklerden oluşan bir organeldir. Genellikle çekirdeğe yakın konumda bulunur."},{"t":"Görevini belirleyelim","a":"Paketleme ve salgı","d":"Golgi, endoplazmik retikulumdan gelen proteinleri ve diğer maddeleri işler, paketler ve salgı için hazırlar. Salgı yapan hücrelerde golgi sayısı fazladır."}],"ans":"Golgi cisimciği maddeleri işler, paketler ve salgılanmak üzere hazırlar"},{"q":"Hayvan hücresinde lizozomun görevi nedir?","steps":[{"t":"Lizozomu tanıyalım","a":"Sindirim kesesi","d":"Lizozom içinde sindirim enzimleri bulunduran, zarla çevrili küçük bir keseciktir. Çoğunlukla hayvan hücrelerinde bulunur."},{"t":"Görevini açıklayalım","a":"Hücre içi sindirim","d":"Lizozomlar hücre içine alınan büyük molekülleri ve yaşlanmış organelleri enzimleriyle parçalar. Böylece hücre içi sindirimi sağlar."}],"ans":"Lizozom enzimleriyle hücre içi sindirimi gerçekleştirir"},{"q":"Hayvan hücresinde kromatin ipliği ile kromozom arasındaki ilişki nedir?","steps":[{"t":"Kromatini tanımlayalım","a":"Açılmış iplik","d":"Kromatin, çekirdek içinde dağınık halde bulunan DNA ve protein ipliğidir. Hücre bölünmesi dışındaki dönemde bu halde bulunur."},{"t":"Kromozomu tanımlayalım","a":"Yoğunlaşmış yapı","d":"Hücre bölüneceği zaman kromatin iplikleri kısalıp kalınlaşarak kromozomları oluşturur. Yani kromozom, yoğunlaşmış kromatindir."}],"ans":"Kromatin iplikleri hücre bölünmesinde kısalıp kalınlaşarak kromozomları oluşturur"},{"q":"Hayvan hücresinde mitokondrinin iç yapısının (iç zar kıvrımları) işleve katkısı nedir?","steps":[{"t":"İç yapıyı inceleyelim","a":"İç zar kıvrımlı","d":"Mitokondrinin çift zarı vardır ve iç zarı krista denilen kıvrımlar oluşturur. Bu kıvrımlar iç yüzeyi artırır."},{"t":"Katkısını açıklayalım","a":"Yüzey artışı","d":"Kıvrımlar sayesinde enerji üretiminin gerçekleştiği yüzey alanı genişler. Böylece daha fazla enerji üretimi mümkün olur."}],"ans":"İç zar kıvrımları yüzey alanını artırarak daha fazla enerji üretimine olanak sağlar"},{"q":"Hayvan hücresinde çekirdekçiğin (nükleolus) görevi nedir?","steps":[{"t":"Çekirdekçiği tanıyalım","a":"Çekirdek içinde","d":"Çekirdekçik, çekirdeğin içinde koyu görünen, zarsız bir yapıdır. Genellikle yuvarlak görünür."},{"t":"Görevini belirleyelim","a":"Ribozom üretimi","d":"Çekirdekçik ribozomların yapımında görev alan bileşenlerin üretildiği yerdir. Bu nedenle protein sentezi ile dolaylı olarak ilişkilidir."}],"ans":"Çekirdekçik ribozom yapımında görev alan bileşenlerin üretiminden sorumludur"},{"q":"Hayvan hücresinde hücre zarının yapısında bulunan temel moleküller nelerdir?","steps":[{"t":"Temel yapıyı belirleyelim","a":"Lipit ve protein","d":"Hücre zarı temel olarak çift sıralı fosfolipit tabakası ve bu tabaka içine yerleşmiş proteinlerden oluşur. Bu yapı zarın esnek olmasını sağlar."},{"t":"Diğer bileşenleri ekleyelim","a":"Karbonhidrat da var","d":"Zarın dış yüzeyinde proteinlere ve lipitlere bağlı karbonhidratlar da bulunur. Bunlar hücrelerin tanınmasında rol oynar."}],"ans":"Hücre zarı temel olarak fosfolipit, protein ve karbonhidratlardan oluşur"},{"q":"Hayvan hücresinde sentrozomun yapısını oluşturan birimler nelerdir?","steps":[{"t":"Sentrozomu inceleyelim","a":"İki sentriyol","d":"Sentrozom genellikle birbirine dik konumlanmış iki sentriyolden oluşur. Bu yapı çekirdeğin yakınında bulunur."},{"t":"Görevini hatırlayalım","a":"İğ ipliği","d":"Sentriyoller hücre bölünmesi sırasında iğ ipliklerinin oluşumunda görev alır. Bu iplikler kromozomların hareketini sağlar."}],"ans":"Sentrozom birbirine dik konumlanmış iki sentriyolden oluşur"},{"q":"Hayvan hücresinde peroksizom organelinin görevi nedir?","steps":[{"t":"Peroksizomu tanıyalım","a":"Zarlı kesecik","d":"Peroksizom zarla çevrili küçük bir keseciktir ve içinde özel enzimler bulunur. Karaciğer ve böbrek hücrelerinde sayıca fazladır."},{"t":"Görevini açıklayalım","a":"Zararsızlaştırma","d":"Peroksizomlar bazı zararlı maddeleri parçalayarak zararsız hale getirir. Özellikle hidrojen peroksiti su ve oksijene ayırır."}],"ans":"Peroksizom zararlı maddeleri ve hidrojen peroksiti parçalayarak zararsız hale getirir"},{"q":"Hayvan hücresinde mitokondrinin kendine ait DNA bulundurmasının anlamı nedir?","steps":[{"t":"Mitokondri DNAsını belirleyelim","a":"Kendi DNAsı var","d":"Mitokondri, çekirdek DNAsından farklı olarak kendine ait küçük bir DNAya sahiptir. Bu DNA mitokondri içinde bulunur."},{"t":"Anlamını açıklayalım","a":"Kendini eşler","d":"Kendi DNAsı sayesinde mitokondri kısmen kendini eşleyebilir ve bazı proteinlerini üretebilir. Bu, onu yarı bağımsız bir organel yapar."}],"ans":"Kendi DNAsı sayesinde mitokondri kısmen kendini eşleyebilir ve yarı bağımsız davranır"},{"q":"Hayvan hücresinde aktif taşıma sırasında neden enerji harcanır?","steps":[{"t":"Aktif taşımayı tanımlayalım","a":"Yoğunluğa karşı","d":"Aktif taşıma, maddenin az yoğun ortamdan çok yoğun ortama doğru taşınmasıdır. Yani derişim farkına ters yönde gerçekleşir."},{"t":"Enerji ihtiyacını açıklayalım","a":"ATP gerekir","d":"Derişime ters yönde taşıma kendiliğinden olmaz, bu yüzden enerji gerekir. Hücre bu enerjiyi ATP olarak harcar."}],"ans":"Madde derişim farkına ters yönde taşındığı için ATP şeklinde enerji harcanır"},{"q":"Hayvan hücresinde fagositoz olayını kısaca açıklayınız.","steps":[{"t":"Fagositozu tanımlayalım","a":"Katı madde alımı","d":"Fagositoz, hücrenin büyük katı parçacıkları zarını uzatıp sararak içeri almasıdır. Bir tür hücre içine alma olayıdır."},{"t":"Sonucunu belirtelim","a":"Koful oluşur","d":"Alınan katı madde zarla çevrilerek bir koful içine alınır. Daha sonra lizozom enzimleriyle sindirilir."}],"ans":"Fagositoz, hücrenin büyük katı parçacıkları zarıyla sararak koful içinde içine almasıdır"},{"q":"Hayvan hücresinde difüzyon olayı nasıl gerçekleşir?","steps":[{"t":"Difüzyonu tanımlayalım","a":"Çoktan aza","d":"Difüzyon, maddelerin çok yoğun oldukları ortamdan az yoğun oldukları ortama doğru yayılmasıdır. Derişim farkı nedeniyle gerçekleşir."},{"t":"Enerji durumunu belirtelim","a":"Enerjisiz","d":"Difüzyon derişim farkı yönünde olduğu için enerji harcanmaz. Bu yüzden pasif bir taşıma şeklidir."}],"ans":"Difüzyon, maddelerin çok yoğundan az yoğun ortama doğru enerji harcanmadan yayılmasıdır"}],"zor":[{"q":"Salgı yapan bir hayvan hücresinde sentezlenen bir proteinin hücre dışına çıkana kadar izlediği yolu organeller arasındaki iş birliğiyle açıklayınız.","steps":[{"t":"Sentez aşamasını belirleyelim","a":"Ribozom üretir","d":"Protein sentezi granüllü endoplazmik retikulum üzerindeki ribozomlarda başlar. Burada amino asitler birleştirilerek protein üretilir."},{"t":"Taşıma ve işleme","a":"ER ve golgi","d":"Üretilen protein granüllü endoplazmik retikulum içinde taşınır ve golgi cisimciğine iletilir. Golgide protein işlenir, olgunlaştırılır ve paketlenir."},{"t":"Salgılama aşamasını belirleyelim","a":"Salgı kofulu","d":"Golgide paketlenen protein salgı kofulu içine alınır. Bu koful hücre zarına yaklaşır ve zarla kaynaşarak proteini hücre dışına bırakır (ekzositoz)."}],"ans":"Protein ribozomda üretilir, granüllü ERde taşınır, golgide işlenip paketlenir ve salgı kofuluyla ekzositozla dışarı verilir"},{"q":"Yaşlanmış ya da görevini tamamlamış bir organelin hücre içinde parçalanma süreci hangi organel iş birliğiyle gerçekleşir? Açıklayınız.","steps":[{"t":"Görevli organeli belirleyelim","a":"Lizozom","d":"Hücre içi parçalanmadan sorumlu organel lizozomdur. İçinde güçlü sindirim enzimleri bulundurur."},{"t":"Süreci açıklayalım","a":"Enzimle parçalama","d":"Yaşlanmış organel zarla çevrilerek bir koful oluşturur ve lizozomla birleşir. Lizozom enzimleri organeli yapı taşlarına ayırır."},{"t":"Sonucu belirtelim","a":"Geri dönüşüm","d":"Parçalanan yapı taşları sitoplazmaya bırakılarak yeniden kullanılabilir hale gelir. Böylece hücre kendini yeniler ve geri dönüşüm sağlar."}],"ans":"Yaşlı organel kofulla çevrilip lizozomla birleşir, enzimlerle parçalanır ve yapı taşları geri dönüştürülür"},{"q":"Karaciğer hücrelerinde granülsüz endoplazmik retikulum ve peroksizomların bol bulunmasının nedenini işlevsel olarak açıklayınız.","steps":[{"t":"Karaciğer görevini belirleyelim","a":"Detoksifikasyon","d":"Karaciğer, vücuda giren zararlı ve toksik maddeleri zararsız hale getiren bir organdır. Bu yüzden hücreleri yoğun şekilde madde işler."},{"t":"Organelleri ilişkilendirelim","a":"Zararsızlaştırma","d":"Granülsüz endoplazmik retikulum ilaç ve toksin gibi maddeleri zararsız hale getirmede görev alır. Peroksizomlar da zararlı maddeleri ve hidrojen peroksiti parçalar."},{"t":"Sonuca varalım","a":"Bol bulunma","d":"Karaciğer hücreleri yoğun detoksifikasyon yaptığı için bu organellere fazlaca ihtiyaç duyar. Bu nedenle granülsüz ER ve peroksizomlar bol miktarda bulunur."}],"ans":"Karaciğer yoğun detoksifikasyon yaptığı için zararsızlaştırmada görevli granülsüz ER ve peroksizomlar bol bulunur"},{"q":"Bir hayvan hücresi saf su (hipotonik ortam) içine konulduğunda neden bitki hücresinden farklı olarak patlama riski taşır?","steps":[{"t":"Su hareketini belirleyelim","a":"Su içeri girer","d":"Hücre saf su içine konulduğunda osmozla içeriye su girişi olur. Hücre içindeki çözünen derişimi dış ortamdan fazla olduğu için su hücreye akar."},{"t":"Yapısal farkı belirleyelim","a":"Duvar yok","d":"Hayvan hücresinde bitki hücresindeki gibi sert bir hücre duvarı yoktur. Yalnızca esnek bir hücre zarı bulunur."},{"t":"Sonucu açıklayalım","a":"Patlama riski","d":"Su girişiyle hücre şişer ve hücre zarı bu basınca dayanamayıp yırtılabilir. Bitki hücresi ise duvarı sayesinde şişer ama patlamaz."}],"ans":"Hayvan hücresinde duvar olmadığından osmozla su girince zar basınca dayanamaz ve hücre patlayabilir"},{"q":"Olgun alyuvar hücrelerinde çekirdek ve mitokondri bulunmaması ile bu hücrelerin görevi arasında nasıl bir ilişki vardır?","steps":[{"t":"Alyuvar görevini belirleyelim","a":"Oksijen taşır","d":"Olgun alyuvarların temel görevi oksijen taşımaktır. İçlerindeki hemoglobin proteini oksijene bağlanır."},{"t":"Eksik yapıları değerlendirelim","a":"Çekirdek ve mitokondri yok","d":"Olgun alyuvarda çekirdek ve mitokondri bulunmaz. Çekirdeğin olmaması daha fazla hemoglobine yer açar, mitokondrinin olmaması ise taşıdığı oksijeni tüketmesini engeller."},{"t":"İlişkiyi kuralım","a":"Verimli taşıma","d":"Bu yapıların olmaması alyuvarın daha çok oksijen taşımasını ve taşıdığı oksijeni kullanmadan iletmesini sağlar. Böylece oksijen taşıma görevi daha verimli gerçekleşir."}],"ans":"Çekirdek ve mitokondri olmaması daha çok hemoglobine yer açar ve taşınan oksijenin tüketilmesini önler, böylece oksijen taşıma verimi artar"},{"q":"Hayvan hücresinde hücre iskeletinin (sitoskeleton) bulunmasının hücreye sağladığı işlevsel katkıları açıklayınız.","steps":[{"t":"Hücre iskeletini tanımlayalım","a":"Protein ağı","d":"Hücre iskeleti, sitoplazma içinde uzanan protein ipliklerinden oluşan bir ağdır. Hücrenin her yanına yayılır."},{"t":"Görevlerini belirleyelim","a":"Destek ve hareket","d":"Hücre iskeleti hücreye şekil ve mekanik destek verir, organelleri yerinde tutar. Ayrıca organellerin ve maddelerin hücre içi hareketini sağlar."},{"t":"Önemini açıklayalım","a":"Düzen sağlar","d":"Hücre duvarı bulunmayan hayvan hücresinde iskelet, şekil korunmasında özellikle önemlidir. Bölünme ve hareket gibi olaylarda da düzeni sağlar."}],"ans":"Hücre iskeleti hücreye şekil ve destek verir, organelleri tutar ve hücre içi hareketi sağlar"},{"q":"Bir hayvan hücresinde protein sentezinin durması durumunda golgi cisimciği ve salgı işlevinin nasıl etkileneceğini açıklayınız.","steps":[{"t":"Üretimi değerlendirelim","a":"Protein üretilemez","d":"Protein sentezi durduğunda ribozomlarda yeni protein üretilemez. Bu durumda endoplazmik retikuluma protein aktarılamaz."},{"t":"Golgiyi değerlendirelim","a":"İşlenecek madde yok","d":"Golgi cisimciği işlemek ve paketlemek için endoplazmik retikulumdan gelen proteine ihtiyaç duyar. Protein gelmediğinde golgide işlenecek madde kalmaz."},{"t":"Salgıyı değerlendirelim","a":"Salgı durur","d":"İşlenecek ve paketlenecek protein olmadığı için salgı kofulları oluşamaz. Sonuçta hücrenin salgı işlevi de durur."}],"ans":"Protein üretilemediği için golgiye madde gelmez, paketleme yapılamaz ve hücrenin salgı işlevi durur"},{"q":"Hayvan hücresinde mitokondri ve ribozomların ortak özelliği olan kendi DNAsını ve protein üretimini değerlendirerek endosimbiyoz görüşüne nasıl katkı sağladığını açıklayınız.","steps":[{"t":"Mitokondriyi inceleyelim","a":"Kendi DNAsı var","d":"Mitokondrinin kendine ait DNAsı ve kendi ribozomları vardır. Ayrıca çift zarlı bir yapıya sahiptir ve kısmen kendini eşleyebilir."},{"t":"Endosimbiyoz görüşünü açıklayalım","a":"Eski bakteri","d":"Endosimbiyoz görüşüne göre mitokondri, geçmişte serbest yaşayan bir bakterinin başka bir hücre içine yerleşmesiyle oluşmuştur. Kendi DNAsı ve ribozomu bu görüşü destekler."},{"t":"Katkıyı belirleyelim","a":"Bağımsızlık kanıtı","d":"Mitokondrinin kendi DNAsıyla protein üretebilmesi ve bölünebilmesi, onun bir zamanlar bağımsız yaşayan bir canlı olduğunu düşündürür. Bu durum endosimbiyoz görüşüne güçlü kanıt sağlar."}],"ans":"Mitokondrinin kendi DNAsı ve ribozomuyla protein üretip bölünebilmesi, onun eskiden bağımsız bir bakteri olduğunu öne süren endosimbiyoz görüşünü destekler"},{"q":"Sinir hücrelerinde golgi cisimciği ve endoplazmik retikulumun gelişmiş olmasının işlevle ilişkisini açıklayınız.","steps":[{"t":"Sinir hücresi görevini belirleyelim","a":"İletim ve salgı","d":"Sinir hücreleri uyartı iletir ve bu sırada bazı kimyasal maddeler salgılar. Bu maddelerin çoğu protein yapılıdır."},{"t":"Organel ihtiyacını ilişkilendirelim","a":"Yoğun sentez","d":"Protein ve salgı maddeleri üretmek için endoplazmik retikulum, işlemek ve paketlemek için golgi gereklidir. Sinir hücreleri sürekli madde ürettiğinden bu organellere çok ihtiyaç duyar."},{"t":"Sonuca varalım","a":"Gelişmiş organel","d":"Yoğun protein sentezi ve salgı nedeniyle sinir hücrelerinde bu organeller iyi gelişmiştir. Böylece hücrenin işlevi desteklenir."}],"ans":"Sinir hücreleri yoğun protein sentezi ve salgı yaptığı için golgi ve ER gelişmiştir"},{"q":"Hayvan hücresinde ekzositoz ve endositoz olaylarının zar yüzeyi üzerindeki etkisini karşılaştırınız.","steps":[{"t":"Ekzositozu inceleyelim","a":"Zar artar","d":"Ekzositozda salgı kofulu hücre zarıyla kaynaşarak içeriğini dışarı verir. Bu sırada kofulun zarı hücre zarına eklenir ve zar yüzeyi artar."},{"t":"Endositozu inceleyelim","a":"Zar azalır","d":"Endositozda hücre zarı içe doğru çökerek madde alır ve koful oluşturur. Bu sırada zarın bir kısmı içeri alındığı için zar yüzeyi azalır."},{"t":"Karşılaştırma yapalım","a":"Denge sağlanır","d":"Ekzositoz zar yüzeyini artırırken endositoz azaltır. Bu iki olay birlikte gerçekleşerek hücre zarının yüzeyini dengede tutar."}],"ans":"Ekzositoz zar yüzeyini artırır, endositoz azaltır; ikisi birlikte zar yüzeyini dengede tutar"},{"q":"Hayvan hücresinde ATP üretiminin büyük kısmının mitokondride gerçekleşmesinin hücre için önemini açıklayınız.","steps":[{"t":"ATPyi tanımlayalım","a":"Enerji parası","d":"ATP hücrenin kullandığı temel enerji molekülüdür. Hücredeki birçok faaliyet ATPden sağlanan enerjiyle yürütülür."},{"t":"Üretim yerini belirleyelim","a":"Mitokondri","d":"ATPnin büyük kısmı mitokondride oksijenli solunumla üretilir. Mitokondri besinleri parçalayarak bol enerji elde eder."},{"t":"Önemini açıklayalım","a":"Yaşamın sürmesi","d":"Mitokondride yeterli ATP üretilmesi hücrenin hayatta kalması için zorunludur. Enerji üretimi durursa hücre faaliyetlerini sürdüremez ve ölür."}],"ans":"Mitokondride üretilen ATP hücrenin tüm faaliyetleri için gerekli enerjiyi sağlar, üretim durursa hücre yaşayamaz"},{"q":"Hayvan hücresinde çekirdek zarının çift katlı olması ve por (geçit) içermesi hücre için neden gereklidir?","steps":[{"t":"Çekirdek zarını inceleyelim","a":"Çift katlı zar","d":"Çekirdek zarı iç ve dış olmak üzere iki katlı bir yapıya sahiptir. Bu zar çekirdeğin içini sitoplazmadan ayırır."},{"t":"Porları değerlendirelim","a":"Geçit görevi","d":"Çekirdek zarı üzerinde porlar adı verilen geçitler bulunur. Bu porlar çekirdek ile sitoplazma arasında madde alışverişini sağlar."},{"t":"Gerekliliğini açıklayalım","a":"Bilgi alışverişi","d":"Çift zar kalıtım maddesini korurken porlar gerekli moleküllerin geçişine izin verir. Böylece çekirdekteki bilgiye göre sitoplazmada protein üretimi yönetilebilir."}],"ans":"Çift katlı zar kalıtım maddesini korur, porlar ise çekirdek ile sitoplazma arasındaki gerekli madde alışverişini sağlar"},{"q":"Hayvan hücresinde turgor basıncının bitki hücresindeki kadar belirgin olmamasının nedenini açıklayınız.","steps":[{"t":"Turgor basıncını tanımlayalım","a":"Suyun duvara basıncı","d":"Turgor basıncı, hücre içine giren suyun hücre duvarına yaptığı basınçtır. Bu basınç hücreye sertlik kazandırır."},{"t":"Hayvan hücresini değerlendirelim","a":"Duvar yok","d":"Hayvan hücresinde sert bir hücre duvarı bulunmaz, sadece esnek zar vardır. Bu nedenle suyun basınç yapacağı sert bir yüzey yoktur."},{"t":"Sonuca varalım","a":"Belirgin değil","d":"Hücre duvarı olmadığı için hayvan hücresinde turgor basıncı oluşmaz ya da belirgin değildir. Fazla su girişi hücreyi sertleştirmek yerine patlatma riski oluşturur."}],"ans":"Hayvan hücresinde hücre duvarı olmadığı için suyun basınç yapacağı sert yüzey yoktur, bu yüzden turgor basıncı belirgin değildir"},{"q":"Bir hayvan hücresinde lizozom zarının yırtılması durumunda hücrenin başına ne gelebilir? Açıklayınız.","steps":[{"t":"Lizozom içeriğini hatırlayalım","a":"Sindirim enzimi","d":"Lizozomun içinde güçlü sindirim enzimleri bulunur. Bu enzimler büyük molekülleri parçalama gücüne sahiptir."},{"t":"Yırtılmayı değerlendirelim","a":"Enzim yayılır","d":"Lizozom zarı yırtılırsa içindeki sindirim enzimleri sitoplazmaya yayılır. Enzimler artık kontrolsüz şekilde serbest kalır."},{"t":"Sonucu belirtelim","a":"Hücre kendini sindirir","d":"Sitoplazmaya yayılan enzimler hücrenin kendi yapılarını parçalamaya başlar. Bu durum hücrenin kendi kendini sindirerek ölmesine yol açabilir."}],"ans":"Lizozom enzimleri sitoplazmaya yayılarak hücrenin kendi yapılarını sindirir ve hücre ölebilir"},{"q":"Hayvan hücresinde aktif taşıma ile kolaylaştırılmış difüzyon arasındaki temel farkları enerji ve yön açısından karşılaştırınız.","steps":[{"t":"Aktif taşımayı inceleyelim","a":"Enerjili, terse","d":"Aktif taşıma maddenin az yoğundan çok yoğun ortama, yani derişime ters yönde taşınmasıdır. Bu nedenle ATP şeklinde enerji harcanır."},{"t":"Kolaylaştırılmış difüzyonu inceleyelim","a":"Enerjisiz, yönünde","d":"Kolaylaştırılmış difüzyon maddenin çok yoğundan az yoğun ortama, yani derişim yönünde taşınmasıdır. Taşıyıcı proteinler kullanılır ama enerji harcanmaz."},{"t":"Farkı belirleyelim","a":"Enerji ve yön","d":"İki olay da taşıyıcı protein kullanır ancak aktif taşıma enerji harcayıp derişime ters yönde, kolaylaştırılmış difüzyon enerji harcamadan derişim yönünde gerçekleşir. Temel fark enerji ve taşıma yönüdür."}],"ans":"Aktif taşıma enerji harcayarak derişime ters yönde, kolaylaştırılmış difüzyon enerji harcamadan derişim yönünde gerçekleşir"}]}},"bitkiHucresi":{"ilkokul":{"kolay":[{"q":"Bitki hücresinin en dışında bulunan, hücre zarını da çevreleyen sert yapı nedir?","steps":[{"t":"Dış sert yapıyı bulalım","a":"Hücre duvarı","d":"Bitki hücresinin en dışında sert ve kalın bir yapı bulunur. Bu yapıya hücre duvarı denir."},{"t":"Görevini düşünelim","a":"Destek ve koruma","d":"Hücre duvarı bitki hücresine destek verir ve onu korur. Sayesinde bitki hücresi köşeli ve düzenli bir şekil alır."}],"ans":"Hücre duvarı"},{"q":"Bitki hücresinde besin üretiminden sorumlu olan yeşil renkli organel hangisidir?","steps":[{"t":"Yeşil organeli bulalım","a":"Kloroplast","d":"Bitki hücresinde yeşil renkli küçük yapılar bulunur. Bunlara kloroplast denir."},{"t":"Görevini düşünelim","a":"Besin üretimi","d":"Kloroplast güneş ışığını kullanarak bitkinin besinini üretir. Bu olaya fotosentez denir."}],"ans":"Kloroplast"},{"q":"Bitki hücresinde genellikle tek ve büyük olarak bulunan, içi sıvı dolu yapıya ne ad verilir?","steps":[{"t":"Büyük yapıyı bulalım","a":"Koful","d":"Bitki hücresinde ortada genellikle tek ve büyük bir kese bulunur. Bu keseye koful denir."},{"t":"İçindekini düşünelim","a":"Su ve madde depolar","d":"Bu büyük koful su ve çeşitli maddeleri depolar. Böylece bitki hücresi gerekli maddeleri içinde saklar."}],"ans":"Koful (merkezi koful)"},{"q":"Yaprakların yeşil renkte görünmesinin nedeni bitki hücresindeki hangi organeldir?","steps":[{"t":"Renk veren yapıyı bulalım","a":"Kloroplast","d":"Yaprak hücrelerinde yeşil renkli kloroplastlar bol miktarda bulunur. Bu organeller yaprağa rengini verir."},{"t":"Nedenini düşünelim","a":"Yeşil madde","d":"Kloroplastların içinde yeşil renkli bir madde vardır. Bu madde sayesinde yapraklar yeşil görünür."}],"ans":"Kloroplast"},{"q":"Bitki hücresi neden köşeli ve düzenli bir şekle sahiptir?","steps":[{"t":"Şekli veren yapıyı bulalım","a":"Hücre duvarı","d":"Bitki hücresinin etrafında sert bir hücre duvarı bulunur. Bu duvar hücreye sabit bir şekil verir."},{"t":"Sonucu düşünelim","a":"Köşeli görünüm","d":"Sert duvar sayesinde bitki hücresi köşeli ve düzenli bir kutu gibi görünür. Bu yüzden hayvan hücresinden ayırt edilir."}],"ans":"Sert hücre duvarı bulunduğu için köşeli ve düzenli bir şekle sahiptir"}],"zor":[{"q":"Bir hücrede hem hücre duvarı hem de kloroplast bulunuyorsa bu hücre hangi canlıya ait olabilir? Açıklayınız.","steps":[{"t":"Yapıları belirleyelim","a":"Duvar ve kloroplast","d":"Hücrede sert bir hücre duvarı ve yeşil kloroplastlar var. Bu iki yapı önemli ipuçlarıdır."},{"t":"Karar verelim","a":"Bitki hücresi","d":"Hücre duvarı ve kloroplast bitki hücrelerine özgüdür. Bu yüzden hücre bir bitkiye aittir."}],"ans":"Bitki hücresine aittir"},{"q":"Bitki hücresi kendi besinini üretebilir mi? Hangi organel sayesinde olur?","steps":[{"t":"Organeli bulalım","a":"Kloroplast","d":"Bitki hücresinde besin üreten kloroplast bulunur. Bu organel güneş ışığını kullanır."},{"t":"Sonucu açıklayalım","a":"Üretebilir","d":"Kloroplast sayesinde bitki hücresi kendi besinini üretebilir. Bu yüzden bitki dışarıdan hazır besin almaya ihtiyaç duymaz."}],"ans":"Evet, kloroplast sayesinde bitki hücresi kendi besinini üretebilir"},{"q":"Bir bitki hücresinde büyük merkezi koful suyla dolduğunda hücreye ne olur?","steps":[{"t":"Kofulu inceleyelim","a":"Su dolar","d":"Merkezi koful su ile dolduğunda hacmi artar ve hücre içinde genişler. Bu koful bitki hücresinin büyük bir kısmını kaplar."},{"t":"Sonucu düşünelim","a":"Diri durur","d":"Su dolu koful hücre duvarına basınç yapar ve hücre dik, diri durur. Bu sayede bitkinin yaprakları ve gövdesi sağlam görünür."}],"ans":"Su dolu koful hücre duvarına basınç yapar ve hücre diri, dik durur"},{"q":"Hayvan hücresinden farklı olarak bitki hücresinde hangi iki yapı bulunur?","steps":[{"t":"İlk yapıyı bulalım","a":"Hücre duvarı","d":"Bitki hücresinde hayvan hücresinde olmayan sert bir hücre duvarı vardır. Bu duvar hücreye destek verir."},{"t":"İkinci yapıyı bulalım","a":"Kloroplast","d":"Bitki hücresinde ayrıca besin üreten kloroplast bulunur. Hayvan hücresinde bu organel yoktur."}],"ans":"Hücre duvarı ve kloroplast"},{"q":"Susuz kalan bir bitkinin yapraklarının solmasının hücre düzeyindeki nedeni nedir?","steps":[{"t":"Su durumunu belirleyelim","a":"Koful su kaybeder","d":"Su azaldığında bitki hücresindeki merkezi koful suyunu kaybeder. Böylece koful küçülür ve hücre içi gevşer."},{"t":"Sonucu açıklayalım","a":"Yaprak solar","d":"Koful küçülünce hücre duvarına yapılan basınç azalır ve hücreler diri duramaz. Bu yüzden yapraklar solar ve aşağı sarkar."}],"ans":"Koful su kaybedip küçülünce hücre duvarına basınç azalır ve yapraklar solar"}]},"ortaokul":{"kolay":[{"q":"Bitki ve hayvan hücresinde ortak olarak bulunan üç temel yapıyı belirtiniz.","steps":[{"t":"İlk ortak yapıyı bulalım","a":"Hücre zarı","d":"Hem bitki hem hayvan hücresinde madde geçişini kontrol eden bir hücre zarı bulunur. Bu zar her iki hücrenin de dış sınırını oluşturur."},{"t":"Diğer ortak yapıları bulalım","a":"Sitoplazma ve çekirdek","d":"İki hücrede de organelleri içinde barındıran sitoplazma vardır. Ayrıca her ikisinde de hücreyi yöneten zarla çevrili bir çekirdek bulunur."}],"ans":"Hücre zarı, sitoplazma ve çekirdek"},{"q":"Bitki hücresinin hücre duvarını oluşturan temel madde nedir?","steps":[{"t":"Duvarı oluşturan maddeyi bulalım","a":"Selüloz","d":"Bitki hücre duvarının yapısında temel olarak selüloz adı verilen madde bulunur. Selüloz dayanıklı bir yapı maddesidir."},{"t":"Görevini düşünelim","a":"Dayanıklılık","d":"Selüloz hücre duvarına sertlik ve dayanıklılık kazandırır. Bu sayede bitki hücresi destek bulur ve şeklini korur."}],"ans":"Selüloz"},{"q":"Bitki hücresinde fotosentez olayının gerçekleştiği organel hangisidir ve bu olayda ne üretilir?","steps":[{"t":"Organeli belirleyelim","a":"Kloroplast","d":"Fotosentez bitki hücresinde kloroplast adı verilen organelde gerçekleşir. Kloroplast yeşil renktedir."},{"t":"Ürünü belirleyelim","a":"Besin ve oksijen","d":"Fotosentezde güneş ışığı kullanılarak besin (glikoz) üretilir. Bu olay sırasında ayrıca oksijen de açığa çıkar."}],"ans":"Kloroplastta gerçekleşir ve besin (glikoz) ile oksijen üretilir"},{"q":"Bitki hücresindeki merkezi kofulun başlıca görevleri nelerdir?","steps":[{"t":"Depolama görevini belirleyelim","a":"Madde depolar","d":"Merkezi koful su, besin ve atık maddeleri depolar. Bu sayede hücre içinde gerekli maddeler saklanır."},{"t":"Destek görevini belirleyelim","a":"Basınç sağlar","d":"Su dolu koful hücre duvarına basınç yaparak hücrenin diri durmasını sağlar. Böylece bitki dik durabilir ve solmaz."}],"ans":"Merkezi koful su ve madde depolar, ayrıca basınç yaparak hücrenin diri durmasını sağlar"},{"q":"Bitki hücresinde genellikle sentrozom bulunmaması ne anlama gelir?","steps":[{"t":"Sentrozomu hatırlayalım","a":"Hayvana özgü","d":"Sentrozom çoğunlukla hayvan hücrelerinde bulunan bir organeldir. Hücre bölünmesinde görev alır."},{"t":"Bitki için yorumlayalım","a":"Farklı bölünme","d":"Bitki hücresinde sentrozom genellikle bulunmaz, ancak bitki yine de bölünebilir. Bu, bitki hücresinin bölünmeyi farklı şekilde gerçekleştirdiğini gösterir."}],"ans":"Bitki hücresi sentrozom olmadan da bölünebilir, yani bölünmeyi farklı bir yolla gerçekleştirir"}],"zor":[{"q":"Bitki ve hayvan hücresini koful özellikleri bakımından karşılaştırınız.","steps":[{"t":"Bitki kofulunu inceleyelim","a":"Tek ve büyük","d":"Bitki hücresinde genellikle tek ve büyük bir merkezi koful bulunur. Bu koful hücrenin büyük kısmını kaplar."},{"t":"Hayvan kofulunu inceleyelim","a":"Çok ve küçük","d":"Hayvan hücresinde ise kofullar küçük ve sayıca fazladır. Çoğu zaman geçici olarak oluşur."},{"t":"Karşılaştırmayı yapalım","a":"Belirgin fark","d":"Bitki hücresinin büyük tek kofulu su depolama ve destek görevi yapar; hayvan hücresinin küçük çok kofulu ise farklı geçici görevler üstlenir. Bu, iki hücre arasındaki belirgin bir farktır."}],"ans":"Bitki hücresinde tek ve büyük merkezi koful, hayvan hücresinde küçük ve çok sayıda koful bulunur"},{"q":"Bitki hücresinin hayvan hücresinden farklı olarak kendi besinini üretebilmesinin nedenini açıklayınız.","steps":[{"t":"Bitkideki farkı belirleyelim","a":"Kloroplast var","d":"Bitki hücresinde fotosentez yapan kloroplast bulunur. Hayvan hücresinde bu organel yoktur."},{"t":"Fotosentezi açıklayalım","a":"Işıkla besin","d":"Kloroplast güneş ışığını kullanarak su ve karbondioksitten besin üretir. Bu olaya fotosentez denir."},{"t":"Sonuca varalım","a":"Kendi besinini yapar","d":"Kloroplast sayesinde bitki kendi besinini üretebilir, yani üretici bir canlıdır. Hayvan hücresi ise besinini dışarıdan almak zorundadır."}],"ans":"Bitki hücresinde kloroplast bulunduğu için fotosentezle kendi besinini üretebilir"},{"q":"Bir bitki hücresi tuzlu su (hipertonik ortam) içine konulduğunda neden büzülür? Açıklayınız.","steps":[{"t":"Su yoğunluğunu karşılaştıralım","a":"Dışarısı yoğun","d":"Tuzlu suda çözünen madde derişimi hücre içine göre daha fazladır. Yani dış ortam hücre içinden daha yoğundur."},{"t":"Su hareketini belirleyelim","a":"Su dışarı çıkar","d":"Osmoz nedeniyle su, az yoğun olan hücre içinden çok yoğun olan dış ortama doğru çıkar. Böylece hücre su kaybeder."},{"t":"Sonucu açıklayalım","a":"Koful küçülür","d":"Su kaybeden hücrede koful küçülür ve sitoplazma hücre duvarından ayrılmaya başlar. Bu yüzden hücre büzülür (plazmoliz)."}],"ans":"Tuzlu su daha yoğun olduğu için osmozla hücreden su çıkar, koful küçülür ve hücre büzülür"},{"q":"Bitki hücresinin sert hücre duvarına sahip olması ona hangi avantaj ve dezavantajları sağlar?","steps":[{"t":"Avantajı belirleyelim","a":"Destek ve koruma","d":"Sert hücre duvarı bitki hücresine destek verir ve onu dış etkilerden korur. Ayrıca fazla su girişinde hücrenin patlamasını önler."},{"t":"Dezavantajı belirleyelim","a":"Şekil sabit","d":"Sert duvar nedeniyle bitki hücresi şeklini değiştiremez ve serbestçe hareket edemez. Bu durum hücrenin esnekliğini sınırlar."},{"t":"Sonucu değerlendirelim","a":"Dengeli yapı","d":"Hücre duvarı koruma ve destek sağlarken hareket ve şekil değiştirme yeteneğini kısıtlar. Yani hem yararlı hem de sınırlayıcı bir yapıdır."}],"ans":"Hücre duvarı destek ve koruma sağlar, fazla su girişinde patlamayı önler ama şekil değiştirme ve hareketi kısıtlar"},{"q":"İki bilinmeyen hücre verilmiş; birincide hücre duvarı, büyük koful ve kloroplast varken ikincide bunlar yok ama sentrozom var. Bu hücreleri sınıflandırınız.","steps":[{"t":"Birinci hücreyi inceleyelim","a":"Bitki özellikleri","d":"Birinci hücrede hücre duvarı, büyük merkezi koful ve kloroplast bulunuyor. Bu üç yapı da bitki hücresine özgüdür."},{"t":"İkinci hücreyi inceleyelim","a":"Hayvan özellikleri","d":"İkinci hücrede hücre duvarı ve kloroplast yok ama sentrozom var. Bu özellikler hayvan hücresini işaret eder."},{"t":"Sınıflandırma yapalım","a":"Bitki ve hayvan","d":"Birinci hücre bitki hücresi, ikinci hücre hayvan hücresidir. Yapısal farklar bu sınıflandırmayı net biçimde gösterir."}],"ans":"Birinci hücre bitki hücresi, ikinci hücre hayvan hücresidir"}]},"lise":{"kolay":[{"q":"Bitki hücresinde hücre duvarının yapısında bulunan temel polisakkarit nedir ve bu maddenin yapısı nasıldır?","steps":[{"t":"Temel maddeyi belirleyelim","a":"Selüloz","d":"Bitki hücre duvarının temel yapı maddesi selülozdur. Selüloz bir polisakkarit, yani çok sayıda şeker biriminden oluşan bir moleküldür."},{"t":"Yapısını açıklayalım","a":"Glikoz zincirleri","d":"Selüloz, çok sayıda glikoz molekülünün birbirine bağlanmasıyla oluşan uzun zincirlerden meydana gelir. Bu zincirler bir araya gelerek dayanıklı lifler oluşturur."}],"ans":"Hücre duvarının temel maddesi selülozdur ve glikoz birimlerinin bağlanmasıyla oluşan bir polisakkarittir"},{"q":"Bitki hücresinde plastitlerin (kloroplast, kromoplast, lökoplast) görevleri nelerdir?","steps":[{"t":"Kloroplastı inceleyelim","a":"Fotosentez","d":"Kloroplast yeşil renkli plastittir ve fotosentez yaparak besin üretir. İçinde yeşil renk veren klorofil pigmenti bulunur."},{"t":"Kromoplastı inceleyelim","a":"Renk verir","d":"Kromoplast sarı, turuncu ve kırmızı renk pigmentleri taşır. Çiçek ve meyvelerin renklenmesini sağlar."},{"t":"Lökoplastı inceleyelim","a":"Depolama","d":"Lökoplast renksiz plastittir ve nişasta, yağ gibi besin maddelerini depolar. Özellikle kök ve tohum gibi depo organlarında bulunur."}],"ans":"Kloroplast fotosentez yapar, kromoplast renk verir, lökoplast besin depolar"},{"q":"Bitki hücresinde merkezi kofulu çevreleyen zarın (tonoplast) görevi nedir?","steps":[{"t":"Tonoplastı tanıyalım","a":"Koful zarı","d":"Merkezi kofulu çevreleyen zara tonoplast denir. Bu zar kofulun içeriğini sitoplazmadan ayırır."},{"t":"Görevini açıklayalım","a":"Madde geçişi","d":"Tonoplast kofula giren ve çıkan maddeleri kontrol eder. Böylece koful içindeki su ve madde dengesi düzenlenir."}],"ans":"Tonoplast merkezi kofulu çevreleyip içine giren ve çıkan maddeleri kontrol eder"},{"q":"Bitki hücresinde turgor basıncı nasıl oluşur ve bitkiye ne sağlar?","steps":[{"t":"Oluşumunu belirleyelim","a":"Su basıncı","d":"Merkezi koful su ile dolduğunda hacmi artar ve hücre duvarına doğru basınç yapar. Bu basınca turgor basıncı denir."},{"t":"Faydasını açıklayalım","a":"Dik durma","d":"Turgor basıncı sayesinde bitki hücreleri diri ve gergin durur. Bu da bitkinin dik durmasını ve yapraklarının açık kalmasını sağlar."}],"ans":"Koful suyla dolup duvara basınç yaparak turgor basıncını oluşturur ve bu basınç bitkinin dik durmasını sağlar"},{"q":"Bitki hücresinde mitokondri bulunmasına rağmen neden hâlâ ihtiyaç vardır, çünkü kloroplast da enerji üretmez mi?","steps":[{"t":"Kloroplastı değerlendirelim","a":"Besin üretir","d":"Kloroplast fotosentezle besin (glikoz) üretir, doğrudan kullanılabilir enerji (ATP) sağlamaz. Üretilen besin enerji deposudur."},{"t":"Mitokondriyi değerlendirelim","a":"ATP üretir","d":"Mitokondri, kloroplastın ürettiği besinleri oksijenli solunumla parçalayarak ATP üretir. Hücrenin kullanabileceği enerji bu şekilde elde edilir."},{"t":"Sonuca varalım","a":"İkisi de gerekli","d":"Bitki kloroplastta besin üretse de bu besni enerjiye çevirmek için mitokondriye ihtiyaç duyar. Bu nedenle bitki hücresinde her iki organel de bulunur."}],"ans":"Kloroplast besin üretir, mitokondri bu besinleri ATPye çevirir; bu yüzden bitki hücresinde her iki organel de gereklidir"},{"q":"Bitki hücresinde komşu hücreler arasındaki bağlantıyı sağlayan plazmodesmler nedir?","steps":[{"t":"Plazmodesmi tanıyalım","a":"Sitoplazma köprüsü","d":"Plazmodesmler, komşu bitki hücrelerinin hücre duvarlarındaki ince geçitlerden uzanan sitoplazma bağlantılarıdır. Bu köprüler hücreleri birbirine bağlar."},{"t":"Görevini açıklayalım","a":"Madde alışverişi","d":"Plazmodesmler sayesinde komşu hücreler su, besin ve sinyal maddelerini paylaşabilir. Böylece doku içinde iletişim ve madde alışverişi sağlanır."}],"ans":"Plazmodesmler komşu hücreler arasında sitoplazma köprüsü kurarak madde alışverişi ve iletişimi sağlar"},{"q":"Bitki hücresinde kloroplastın iç yapısında bulunan grana ve stroma kısımlarının görevleri nelerdir?","steps":[{"t":"Granayı inceleyelim","a":"Işık tepkimeleri","d":"Grana, kloroplast içinde üst üste dizilmiş zar keseciklerinden (tilakoit) oluşur. Burada fotosentezin ışığa bağlı tepkimeleri gerçekleşir ve klorofil bulunur."},{"t":"Stromayı inceleyelim","a":"Karanlık tepkimeler","d":"Stroma, kloroplastın içini dolduran sıvı kısımdır. Fotosentezin ışıktan bağımsız tepkimeleri burada gerçekleşir ve besin üretimi tamamlanır."}],"ans":"Granada fotosentezin ışığa bağlı tepkimeleri, stromada ışıktan bağımsız (besin üretimi) tepkimeleri gerçekleşir"},{"q":"Bitki hücresinde ribozomlar hangi bölümlerde bulunabilir?","steps":[{"t":"Genel yerlerini belirleyelim","a":"Sitoplazma ve ER","d":"Ribozomlar sitoplazmada serbest halde veya granüllü endoplazmik retikulum üzerinde bulunabilir. Tüm canlı hücrelerde olduğu gibi bitki hücresinde de vardır."},{"t":"Organel içlerini belirleyelim","a":"Kloroplast ve mitokondri","d":"Bitki hücresinde ribozomlar ayrıca kloroplast ve mitokondri içinde de bulunur. Bu organellerin kendi DNAsı olduğu için kendi ribozomlarına da sahiptir."}],"ans":"Ribozomlar sitoplazmada, granüllü ER üzerinde, ayrıca kloroplast ve mitokondri içinde bulunur"},{"q":"Bitki hücresinde primer (birincil) ve sekonder (ikincil) hücre duvarı arasındaki fark nedir?","steps":[{"t":"Primer duvarı inceleyelim","a":"İnce ve esnek","d":"Primer hücre duvarı genç hücrelerde oluşan ilk duvardır ve incedir. Hücre büyürken esneyebilen bir yapıya sahiptir."},{"t":"Sekonder duvarı inceleyelim","a":"Kalın ve sert","d":"Sekonder hücre duvarı, hücre büyümesini tamamladıktan sonra primer duvarın iç tarafına eklenen kalın bir katmandır. Daha sert ve dayanıklıdır."}],"ans":"Primer duvar ince ve esnek olup büyüyen hücrede bulunur, sekonder duvar kalın ve sert olup büyümesi biten hücrede oluşur"},{"q":"Bitki hücresinde fotosentez ve solunum olaylarının gerçekleştiği organeller hangileridir?","steps":[{"t":"Fotosentez organelini bulalım","a":"Kloroplast","d":"Fotosentez bitki hücresinde kloroplastta gerçekleşir. Burada ışık enerjisiyle besin üretilir."},{"t":"Solunum organelini bulalım","a":"Mitokondri","d":"Oksijenli solunum ise mitokondride gerçekleşir. Burada besinler parçalanarak ATP üretilir."}],"ans":"Fotosentez kloroplastta, oksijenli solunum mitokondride gerçekleşir"},{"q":"Bitki hücresinde nişasta hangi organelde depolanır?","steps":[{"t":"Depo organelini belirleyelim","a":"Lökoplast","d":"Bitki hücresinde besin depolayan renksiz plastitlere lökoplast denir. Nişasta depolayan türüne amiloplast adı verilir."},{"t":"Görevini açıklayalım","a":"Nişasta deposu","d":"Lökoplastlar fotosentezle üretilen fazla glikozu nişasta halinde depolar. Bu depolama özellikle kök, yumru ve tohumlarda yoğundur."}],"ans":"Nişasta lökoplast (amiloplast) içinde depolanır"},{"q":"Bitki hücresinde golgi cisimciğinin hücre duvarı oluşumuna katkısı nedir?","steps":[{"t":"Golgiyi hatırlayalım","a":"Paketleme organeli","d":"Golgi cisimciği maddeleri işleyip paketleyen organeldir. Bitki hücresinde de salgı ve madde hazırlamada görev alır."},{"t":"Duvar oluşumuyla ilişkilendirelim","a":"Duvar maddesi taşır","d":"Golgi, hücre duvarının yapımında kullanılan bazı karbonhidrat maddelerini üretir ve paketler. Bu maddeleri hücre zarına ileterek duvar oluşumuna katkı sağlar."}],"ans":"Golgi cisimciği hücre duvarı yapımında kullanılan karbonhidrat maddelerini üretip duvar oluşumuna katkı sağlar"},{"q":"Bitki hücresinin osmotik dengede (izotonik benzeri durum) olmaması ve genellikle turgorlu kalmasının nedeni nedir?","steps":[{"t":"Su alımını değerlendirelim","a":"Su girişi sürekli","d":"Bitki hücreleri çoğunlukla kendilerinden daha az yoğun ortamda bulunur, bu yüzden osmozla sürekli su alma eğilimindedir. Su koful içine girer."},{"t":"Duvarın rolünü belirleyelim","a":"Duvar sınırlar","d":"Su girişiyle koful şişer ve hücre duvarına basınç yapar. Sert hücre duvarı hücrenin daha fazla su almasını sınırlar ve patlamayı önler."},{"t":"Sonuca varalım","a":"Turgorlu kalır","d":"Bu denge sayesinde bitki hücresi şişkin (turgorlu) durumda kalır ama patlamaz. Böylece bitki dik ve diri kalabilir."}],"ans":"Bitki hücresi sürekli su alma eğilimindedir, hücre duvarı bu su girişini sınırlayarak hücreyi turgorlu ama patlamadan tutar"},{"q":"Bitki hücresinde kloroplast ve mitokondrinin çift zarlı olması ve kendi DNAsını taşıması ne anlama gelir?","steps":[{"t":"Yapısal özelliği belirleyelim","a":"Çift zar ve DNA","d":"Hem kloroplast hem mitokondri çift zarlı yapıdadır ve kendine ait DNA taşır. Ayrıca kendi ribozomlarına sahiptir."},{"t":"Anlamını açıklayalım","a":"Yarı bağımsız","d":"Kendi DNAsı ve ribozomu sayesinde bu organeller kısmen kendilerini eşleyebilir ve bazı proteinlerini üretebilir. Bu onları yarı bağımsız organeller yapar."},{"t":"Görüşle ilişkilendirelim","a":"Endosimbiyoz","d":"Bu özellikler, kloroplast ve mitokondrinin geçmişte bağımsız yaşayan hücrelerden geldiğini öne süren endosimbiyoz görüşünü destekler. Yani bu organeller eskiden serbest yaşayan canlılar olabilir."}],"ans":"Çift zar ve kendi DNAsı kloroplast ile mitokondrinin yarı bağımsız olduğunu gösterir ve endosimbiyoz görüşünü destekler"},{"q":"Bitki hücresinde su ve minerallerin alınmasında osmoz olayının önemini açıklayınız.","steps":[{"t":"Osmozu tanımlayalım","a":"Su geçişi","d":"Osmoz, suyun az yoğun ortamdan çok yoğun ortama yarı geçirgen zardan geçişidir. Bitki hücresinde su bu yolla içeri girer."},{"t":"Önemini açıklayalım","a":"Su alımı","d":"Bitki kökleri topraktaki suyu osmozla hücrelerine alır. Bu su hücre içindeki kofulu doldurarak turgoru ve madde taşınmasını destekler."}],"ans":"Osmoz, bitki hücresinin topraktan su almasını sağlayarak turgoru ve su dengesini korur"}],"zor":[{"q":"Bitki hücresi hipotonik bir ortama konulduğunda turgor durumuna nasıl ulaşır ve aynı koşulda hayvan hücresinden farkı nedir?","steps":[{"t":"Su hareketini belirleyelim","a":"Su içeri girer","d":"Hipotonik ortamda dış ortam hücre içinden daha az yoğundur, bu yüzden osmozla hücreye su girer. Su merkezi kofula dolar."},{"t":"Bitki hücresini değerlendirelim","a":"Turgora ulaşır","d":"Su girişiyle koful şişer ve hücre duvarına basınç yapar; bu basınca turgor denir. Sert hücre duvarı su girişini sınırladığından hücre şişer ama patlamaz."},{"t":"Hayvanla karşılaştıralım","a":"Hayvan patlar","d":"Aynı ortamda hayvan hücresinde duvar olmadığı için su girişi sürer ve hücre zarı dayanamayıp patlayabilir. Yani bitki hücresi turgorlanırken hayvan hücresi patlama riski taşır."}],"ans":"Bitki hücresinde su girince koful şişer ve duvar sayesinde turgora ulaşıp patlamaz, hayvan hücresi ise duvar olmadığından aynı ortamda patlayabilir"},{"q":"Plazmoliz olmuş bir bitki hücresinin tekrar normal hâline (turgor) dönebilmesi için hangi koşul gereklidir? Süreci açıklayınız.","steps":[{"t":"Plazmolizi hatırlayalım","a":"Su kaybetmiş","d":"Plazmoliz, hücrenin hipertonik ortamda su kaybedip büzülmesi ve sitoplazmanın duvardan ayrılmasıdır. Koful küçülmüştür."},{"t":"Gerekli koşulu belirleyelim","a":"Hipotonik ortam","d":"Hücrenin tekrar su alabilmesi için hipotonik veya daha az yoğun bir ortama konulması gerekir. Böylece su yeniden hücre içine girebilir."},{"t":"Süreci açıklayalım","a":"Deplazmoliz","d":"Su girişiyle koful tekrar şişer, sitoplazma duvara doğru genişler ve hücre eski turgor durumuna döner. Bu olaya deplazmoliz denir."}],"ans":"Hücrenin hipotonik bir ortama konulması gerekir; su alınca koful şişer ve hücre deplazmolizle turgora döner"},{"q":"Bitki yapraklarında fotosentez yapan hücrelerde hem kloroplast hem mitokondrinin bol bulunması ve bunların gün içinde birbirini tamamlamasını açıklayınız.","steps":[{"t":"Gündüz durumunu inceleyelim","a":"Fotosentez baskın","d":"Gündüz ışık varken kloroplast fotosentez yaparak besin ve oksijen üretir. Bu sırada bol miktarda glikoz oluşur."},{"t":"Solunumla ilişkilendirelim","a":"Mitokondri kullanır","d":"Mitokondri, kloroplastın ürettiği glikozu oksijenle parçalayarak ATP üretir. Yani fotosentez ürünü solunumda hammadde olur."},{"t":"Tamamlayıcılığı açıklayalım","a":"Madde döngüsü","d":"Fotosentezde üretilen oksijen ve glikoz solunumda kullanılır, solunumda açığa çıkan karbondioksit ise fotosentezde kullanılır. Bu nedenle iki organel birbirini tamamlar ve yaprak hücrelerinde ikisi de bol bulunur."}],"ans":"Kloroplast besin ve oksijen üretir, mitokondri bunları kullanarak ATP üretir ve açığa çıkan karbondioksiti fotosenteze geri verir; iki organel birbirini tamamladığı için ikisi de bol bulunur"},{"q":"Bitki hücresinde merkezi kofulun büyük olmasının hücre ekonomisi ve metabolizması açısından avantajını açıklayınız.","steps":[{"t":"Kofulun hacmini değerlendirelim","a":"Büyük hacim","d":"Merkezi koful bitki hücresinin büyük bölümünü kaplar ve hücreyi şişkin tutar. Bu büyük hacim çoğunlukla su ve depolanan maddelerle doludur."},{"t":"Ekonomik avantajı belirleyelim","a":"Az sitoplazma","d":"Hücre hacmini büyük kofulla doldurmak, daha az sitoplazma ile büyük hücre hacmine ulaşmayı sağlar. Böylece hücre daha az madde harcayarak büyür."},{"t":"Metabolik avantajı açıklayalım","a":"Depo ve denge","d":"Büyük koful besin, atık ve iyon depolayarak sitoplazma dengesini korur ve turgorla destek sağlar. Bu da hücrenin hem ekonomik hem dengeli çalışmasına olanak verir."}],"ans":"Büyük merkezi koful, az sitoplazmayla büyük hacim sağlar, madde depolar ve turgorla destek vererek hücreye ekonomik ve metabolik avantaj sunar"},{"q":"Bir bitki hücresinde hücre duvarının seçici geçirgen olmaması ama hücre zarının seçici geçirgen olması neyi gösterir? Madde geçişi açısından açıklayınız.","steps":[{"t":"Hücre duvarını inceleyelim","a":"Tam geçirgen","d":"Hücre duvarı selülozdan oluşur ve gözenekli bir yapıdadır; su ve çözünmüş maddeleri büyük ölçüde geçirir. Yani seçici davranmaz, tam geçirgendir."},{"t":"Hücre zarını inceleyelim","a":"Seçici geçirgen","d":"Hücre zarı ise hangi maddenin geçeceğine karar veren seçici geçirgen bir yapıdadır. Asıl madde kontrolü zarda yapılır."},{"t":"Sonucu açıklayalım","a":"Kontrol zarda","d":"Bu durum, bitki hücresinde madde geçişinin asıl kontrolünün hücre zarı tarafından yapıldığını gösterir. Hücre duvarı sadece destek ve koruma sağlar, geçişi seçmez."}],"ans":"Hücre duvarı tam geçirgen olup destek sağlar, asıl madde geçiş kontrolü ise seçici geçirgen hücre zarı tarafından yapılır"},{"q":"Bitki ve hayvan hücresini hücre bölünmesi sırasında sitoplazma bölünmesi (sitokinez) açısından karşılaştırınız.","steps":[{"t":"Hayvan hücresini inceleyelim","a":"Boğumlanma","d":"Hayvan hücresinde sitoplazma, hücre zarının ortadan içe doğru boğumlanmasıyla ikiye ayrılır. Duvar olmadığı için zar kolayca içe çöker."},{"t":"Bitki hücresini inceleyelim","a":"Ara lamel","d":"Bitki hücresinde sert duvar nedeniyle boğumlanma olamaz, bunun yerine ortada bir ara plak (orta lamel) oluşur. Bu plak büyüyerek hücreyi ikiye böler."},{"t":"Farkı belirleyelim","a":"Duvar nedeniyle","d":"İki hücre arasındaki bu fark, hücre duvarının varlığından kaynaklanır. Hayvan hücresi boğumlanırken bitki hücresi ara lamel oluşturarak bölünür."}],"ans":"Hayvan hücresinde sitoplazma boğumlanarak, bitki hücresinde ise ara lamel (hücre plağı) oluşarak bölünür; fark hücre duvarından kaynaklanır"},{"q":"Sonbaharda yaprakların sararıp kızarmasının bitki hücresindeki plastitlerle ilişkisini açıklayınız.","steps":[{"t":"Yeşil rengi açıklayalım","a":"Klorofil baskın","d":"Yapraklarda yeşil renk, kloroplasttaki klorofil pigmentinden kaynaklanır. Yaz boyunca klorofil bol olduğu için diğer renkler görünmez."},{"t":"Sonbahar değişimini belirleyelim","a":"Klorofil azalır","d":"Sonbaharda ışık ve sıcaklık azalınca klorofil parçalanır ve miktarı azalır. Yeşil renk kaybolmaya başlar."},{"t":"Diğer pigmentleri açıklayalım","a":"Sarı ve kırmızı","d":"Klorofil azalınca kromoplastlardaki sarı ve turuncu pigmentler ile oluşan kırmızı pigmentler ortaya çıkar. Bu yüzden yapraklar sararıp kızarır."}],"ans":"Sonbaharda klorofil parçalanıp azalınca kromoplasttaki sarı, turuncu ve kırmızı pigmentler görünür hale gelir ve yapraklar sararıp kızarır"},{"q":"Bitki hücresinde kloroplast sayısının yaprak hücrelerinde kök hücrelerine göre fazla olmasının nedenini açıklayınız.","steps":[{"t":"Yaprak görevini belirleyelim","a":"Fotosentez yeri","d":"Yapraklar bitkinin ışık alan ve fotosentez yapan organlarıdır. Fotosentez kloroplastlarda gerçekleşir."},{"t":"Kök görevini belirleyelim","a":"Su ve mineral","d":"Kökler ise toprak altında bulunur, ışık almaz ve görevi su ile mineral almaktır. Bu yüzden kökte fotosenteze gerek yoktur."},{"t":"İlişkiyi kuralım","a":"Çok kloroplast","d":"Fotosentez ışık alan yaprak hücrelerinde yoğun olduğu için bu hücrelerde kloroplast sayısı fazladır. Işık almayan kök hücrelerinde ise kloroplast az ya da yoktur."}],"ans":"Fotosentez ışık alan yapraklarda yoğun yapıldığı için yaprak hücrelerinde kloroplast çoktur, ışık almayan köklerde ise az ya da yoktur"},{"q":"Bitki hücresinde hücre duvarının lignin maddesiyle güçlenmesinin (odunlaşma) bitki için önemini açıklayınız.","steps":[{"t":"Lignini tanıyalım","a":"Sertleştirici madde","d":"Lignin, hücre duvarına eklenen sert ve dayanıklı bir maddedir. Özellikle bitkinin odunsu kısımlarında bulunur."},{"t":"Etkisini açıklayalım","a":"Duvar sertleşir","d":"Lignin eklenince hücre duvarı daha sert ve sağlam hale gelir. Bu olaya odunlaşma denir ve hücre ölü hale gelebilir."},{"t":"Önemini belirleyelim","a":"Destek ve diklik","d":"Odunlaşmış hücreler bitkiye mekanik destek sağlar ve dik durmasına yardımcı olur. Ayrıca su taşıyan boruların açık kalmasını destekler."}],"ans":"Lignin hücre duvarını sertleştirip odunlaştırarak bitkiye mekanik destek sağlar, dik durmasına ve su iletim borularının açık kalmasına yardım eder"},{"q":"Bitki hücresinde su iletimi sırasında kofulun ve hücre duvarının birlikte rolünü açıklayınız.","steps":[{"t":"Kofulun rolünü belirleyelim","a":"Su deposu","d":"Merkezi koful suyu depolar ve hücrenin su dengesini ayarlar. Koful su aldıkça hücre şişer."},{"t":"Duvarın rolünü belirleyelim","a":"Sınır ve basınç","d":"Su dolu koful hücre duvarına basınç yapar, duvar ise bu basınca karşı koyarak hücreyi şekilde tutar. Böylece turgor basıncı oluşur."},{"t":"Birlikte rolü açıklayalım","a":"Su dengesi","d":"Koful ve duvar birlikte çalışarak hücrenin su alımını dengeler ve hücreyi diri tutar. Bu denge bitkinin su iletimini ve dikliğini destekler."}],"ans":"Koful su depolayıp duvara basınç yapar, hücre duvarı bu basınca karşı koyar; birlikte turgoru ve su dengesini sağlayarak hücreyi diri tutar"},{"q":"Bitki hücresinde fazla üretilen glikozun nişastaya çevrilerek depolanmasının hücre için avantajını açıklayınız.","steps":[{"t":"Glikozun durumunu değerlendirelim","a":"Suda çözünür","d":"Glikoz suda çözünen küçük bir moleküldür. Hücre içinde fazla glikoz birikirse osmotik dengeyi bozarak hücreye fazla su çekebilir."},{"t":"Nişastayı değerlendirelim","a":"Çözünmez depo","d":"Glikoz molekülleri birleştirilerek suda çözünmeyen nişastaya çevrilir. Nişasta osmotik dengeyi etkilemeden depolanabilir."},{"t":"Avantajı belirleyelim","a":"Güvenli depolama","d":"Glikozu nişasta olarak depolamak hem osmotik dengeyi korur hem de büyük miktarda enerjiyi az yerde saklamayı sağlar. Bu, hücre için güvenli ve verimli bir depolama yöntemidir."}],"ans":"Glikoz suda çözünüp osmotik dengeyi bozabilir; nişastaya çevrilince çözünmez ve osmozu etkilemeden büyük miktarda enerji güvenle depolanır"},{"q":"Bitki ve hayvan hücresinde besin depolama maddeleri açısından farkı açıklayınız.","steps":[{"t":"Bitki hücresini inceleyelim","a":"Nişasta depolar","d":"Bitki hücresi fazla glikozu nişasta halinde depolar. Nişasta lökoplastlarda saklanan bitkisel depo karbonhidratıdır."},{"t":"Hayvan hücresini inceleyelim","a":"Glikojen depolar","d":"Hayvan hücresi ise fazla glikozu glikojen halinde depolar. Glikojen özellikle karaciğer ve kas hücrelerinde bulunur."},{"t":"Farkı belirleyelim","a":"Nişasta-glikojen","d":"Bitki hücresi depo karbonhidratı olarak nişasta, hayvan hücresi ise glikojen kullanır. Bu, iki hücre arasındaki önemli bir metabolik farktır."}],"ans":"Bitki hücresi fazla glikozu nişasta, hayvan hücresi ise glikojen olarak depolar"},{"q":"Bitki hücresinde kloroplastın hareket edebilmesi (ışığa göre konum değiştirmesi) hücreye nasıl bir fayda sağlar?","steps":[{"t":"Hareketi tanımlayalım","a":"Işığa göre yer değiştirir","d":"Kloroplastlar hücre içinde ışığın şiddetine göre yer değiştirebilir. Az ışıkta yüzeye yakın, çok şiddetli ışıkta ise yana çekilebilir."},{"t":"Az ışık durumunu açıklayalım","a":"Işığı yakalar","d":"Az ışık olduğunda kloroplastlar ışık gelen yüzeye yaklaşarak daha çok ışık yakalar. Böylece fotosentez verimi artar."},{"t":"Fazla ışık durumunu açıklayalım","a":"Korunma","d":"Çok şiddetli ışıkta kloroplastlar yana çekilerek aşırı ışıktan zarar görmekten korunur. Bu hareket fotosentezi en uygun düzeyde tutar."}],"ans":"Kloroplastın ışığa göre konum değiştirmesi az ışıkta daha çok ışık yakalamayı, fazla ışıkta zarardan korunmayı sağlayarak fotosentezi en uygun düzeyde tutar"},{"q":"Bir bitki hücresinin hücre duvarı deneysel olarak uzaklaştırılırsa (protoplast elde edilirse) bu hücre hipotonik ortamda nasıl davranır?","steps":[{"t":"Protoplastı tanımlayalım","a":"Duvarsız hücre","d":"Hücre duvarı uzaklaştırıldığında geriye sadece zarla çevrili hücre içeriği kalır, buna protoplast denir. Artık sert duvar yoktur."},{"t":"Hipotonik etkiyi belirleyelim","a":"Su girer","d":"Hipotonik ortamda osmozla hücreye su girer ve hücre şişmeye başlar. Normalde duvar bu şişmeyi sınırlardı."},{"t":"Sonucu açıklayalım","a":"Patlayabilir","d":"Duvar olmadığı için su girişini sınırlayacak bir yapı kalmaz ve zar basınca dayanamayıp patlayabilir. Yani duvarsız bitki hücresi tıpkı hayvan hücresi gibi davranır."}],"ans":"Duvar olmadığı için protoplast hipotonik ortamda su alıp şişer ve hayvan hücresi gibi patlayabilir"},{"q":"Bitki hücresinde fotosentez ürünü oksijenin bir kısmının aynı hücredeki mitokondri tarafından kullanılmasının madde ekonomisi açısından önemini açıklayınız.","steps":[{"t":"Oksijen üretimini belirleyelim","a":"Kloroplast üretir","d":"Fotosentez sırasında kloroplastta oksijen açığa çıkar. Bu oksijenin bir kısmı hücre içinde kalır."},{"t":"Mitokondri kullanımını açıklayalım","a":"Solunumda kullanır","d":"Mitokondri oksijenli solunum yaparken oksijene ihtiyaç duyar. Kloroplastın ürettiği oksijeni doğrudan kullanabilir."},{"t":"Ekonomik önemi belirleyelim","a":"İç döngü","d":"Oksijenin hücre içinde üretilip yine hücre içinde kullanılması, dışarıdan oksijen alma ihtiyacını azaltır. Bu iç döngü, hücreye madde ekonomisi açısından verimlilik sağlar."}],"ans":"Kloroplastın ürettiği oksijenin aynı hücredeki mitokondri tarafından kullanılması dışarıdan oksijen alma ihtiyacını azaltarak hücreye madde ekonomisi sağlar"}]}},"prokaryotOkaryot":{"ilkokul":{"kolay":[{"q":"Bakterilerin içinde belirgin bir çekirdek var mıdır?","steps":[{"t":"Bakteri nedir?","a":"Küçük tek hücreli canlı","d":"Bakteriler çok küçük, tek hücreden oluşan canlılardır. Gözle görülmezler ve mikroskopla incelenirler. Her yerde, suda, toprakta ve hatta vücudumuzda bulunurlar."},{"t":"İçinde çekirdek var mı?","a":"Belirgin çekirdek yok","d":"Bakterilerde gerçek bir çekirdek bulunmaz. Çekirdek görevini gören madde hücrenin içine dağılmış durumdadır. Bu yüzden bakterilere çekirdeksiz canlılar denir."}],"ans":"Hayır, bakterilerde belirgin bir çekirdek yoktur; onlar çekirdeksiz canlılardır."},{"q":"İnsan hücresinde çekirdek bulunur mu?","steps":[{"t":"İnsan hücresi nasıldır?","a":"Gelişmiş bir hücre","d":"İnsan vücudu çok sayıda hücreden oluşur. Bu hücreler bakterilere göre daha büyük ve gelişmiştir. İçlerinde küçük bölümler ve bir yönetim merkezi vardır."},{"t":"Çekirdek var mı?","a":"Evet, çekirdek var","d":"İnsan hücresinin tam ortasında bir çekirdek bulunur. Bu çekirdek hücreyi yönetir ve önemli bilgileri saklar. Çekirdeği olan hücrelere çekirdekli hücre denir."}],"ans":"Evet, insan hücresinde çekirdek bulunur."},{"q":"Hangisi daha küçüktür: bir bakteri mi yoksa bir insan hücresi mi?","steps":[{"t":"Bakterinin boyutu","a":"Çok küçük","d":"Bakteriler canlılar arasında en küçüklerden biridir. Bir bakteriyi görmek için güçlü mikroskoplar gerekir. Çok küçük oldukları için çıplak gözle fark edilmezler."},{"t":"Karşılaştırma","a":"Bakteri daha küçük","d":"İnsan hücresi bir bakteriye göre çok daha büyüktür. Bir insan hücresinin içine birçok bakteri sığabilir. Yani bakteri, insan hücresinden daha küçüktür."}],"ans":"Bakteri, insan hücresinden daha küçüktür."},{"q":"Çekirdeksiz canlılara verilen ad nedir?","steps":[{"t":"Çekirdeği olmayan hücreler","a":"Bakteriler örnektir","d":"Bazı canlıların hücrelerinde gerçek çekirdek yoktur. Bakteriler bu canlılara güzel bir örnektir. Onların kalıtım maddesi hücre içinde serbest durur."},{"t":"Bu canlıların adı","a":"Prokaryot denir","d":"Çekirdeği olmayan canlılara prokaryot adı verilir. Prokaryot kelimesi çekirdeksiz anlamına gelir. Bakteriler en bilinen prokaryot canlılardır."}],"ans":"Çekirdeksiz canlılara prokaryot denir."},{"q":"Çekirdeği olan canlılara ne ad verilir?","steps":[{"t":"Çekirdekli hücreler","a":"İnsan ve bitki örnek","d":"İnsanların, hayvanların ve bitkilerin hücrelerinde gerçek bir çekirdek bulunur. Bu çekirdek hücrenin yöneticisidir. Çekirdek, hücrenin önemli bilgilerini korur."},{"t":"Bu canlıların adı","a":"Ökaryot denir","d":"Çekirdeği olan canlılara ökaryot adı verilir. Ökaryot kelimesi gerçek çekirdekli anlamına gelir. İnsan, bitki ve hayvanlar ökaryot canlılardır."}],"ans":"Çekirdeği olan canlılara ökaryot denir."}],"zor":[{"q":"Bir bakteri ile bir bitki hücresinin en önemli farkı nedir?","steps":[{"t":"Bakteriye bakalım","a":"Çekirdeği yok","d":"Bakteri tek hücreli ve çok küçük bir canlıdır. İçinde gerçek bir çekirdek bulunmaz. Kalıtım maddesi hücrenin içinde serbest durur."},{"t":"Bitki hücresine bakalım","a":"Çekirdeği var","d":"Bitki hücresi daha büyüktür ve gelişmiştir. İçinde gerçek bir çekirdek bulunur. Bu çekirdek hücrenin yönetim merkezidir."},{"t":"Farkı bulalım","a":"Çekirdek farkı","d":"Bakteride çekirdek yokken bitki hücresinde çekirdek vardır. Bu en önemli farktır. Yani biri çekirdeksiz, diğeri çekirdeklidir."}],"ans":"En önemli fark çekirdektir: bakteride çekirdek yokken bitki hücresinde gerçek bir çekirdek bulunur."},{"q":"Neden bakterileri çıplak gözle göremeyiz?","steps":[{"t":"Bakterinin boyutu","a":"Çok küçük","d":"Bakteriler canlıların en küçüklerindendir. Boyutları gözümüzün görebileceğinden çok daha azdır. Bu yüzden onları doğrudan göremeyiz."},{"t":"Nasıl görürüz?","a":"Mikroskopla","d":"Bakterileri görmek için mikroskop adı verilen bir aleti kullanırız. Mikroskop küçük şeyleri büyük gösterir. Böylece bakterileri inceleyebiliriz."}],"ans":"Bakteriler çok küçük oldukları için çıplak gözle görülemez; onları görmek için mikroskop gerekir."},{"q":"Bir bakterinin kalıtım maddesi hücrenin neresinde durur?","steps":[{"t":"Bakteride çekirdek yok","a":"Çekirdek bölmesi yok","d":"Bakterilerde gerçek bir çekirdek bölümü bulunmaz. Yani kalıtım maddesini saklayan ayrı bir oda yoktur. Bu durum bakteriyi çekirdekli hücrelerden ayırır."},{"t":"Madde nerede?","a":"Hücre içinde serbest","d":"Bakterinin kalıtım maddesi hücrenin sitoplazmasında serbest olarak durur. Bir zarla çevrili değildir. Hücrenin içine dağılmış gibidir."}],"ans":"Bakterinin kalıtım maddesi, çekirdek olmadığı için hücre içinde serbest olarak durur."},{"q":"Tek hücreli olduğu hâlde bakteri neden canlı sayılır?","steps":[{"t":"Canlı olmanın işaretleri","a":"Beslenir ve çoğalır","d":"Canlılar beslenir, büyür ve çoğalır. Bu özellikler canlı olmanın işaretleridir. Bir varlığın canlı olup olmadığını bu işaretlerle anlarız."},{"t":"Bakteri ne yapar?","a":"O da yapar","d":"Bakteriler de beslenir ve sayılarını artırarak çoğalır. Tek hücreli olsalar da yaşamsal işleri yaparlar. Bu yüzden bakteriler canlı sayılır."}],"ans":"Bakteri beslenip çoğalabildiği için, tek hücreli olsa da canlı sayılır."},{"q":"Çekirdekli ve çekirdeksiz hücrelerden hangisi daha basit yapılıdır?","steps":[{"t":"Çekirdeksiz hücre","a":"Bakteri gibi","d":"Çekirdeksiz hücrelerde gerçek çekirdek ve zarlı bölümler yoktur. Bu hücreler daha az parçaya sahiptir. Bakteriler bu tür hücrelere örnektir."},{"t":"Çekirdekli hücre","a":"İnsan gibi","d":"Çekirdekli hücrelerde çekirdek ve birçok küçük bölüm bulunur. Bu hücreler daha çok parça içerir. İnsan hücreleri bu türe örnektir."},{"t":"Karşılaştırma","a":"Çekirdeksiz daha basit","d":"Çekirdeksiz hücrede daha az parça olduğu için yapı daha basittir. Çekirdekli hücre ise daha karmaşıktır. Yani bakteriler daha basit yapılıdır."}],"ans":"Çekirdeksiz hücreler (bakteriler gibi) daha az parça içerdiği için daha basit yapılıdır."}]},"ortaokul":{"kolay":[{"q":"Prokaryot ve ökaryot hücreyi ayıran temel özellik nedir?","steps":[{"t":"Prokaryot hücre","a":"Çekirdeği yok","d":"Prokaryot hücrelerde zarla çevrili gerçek bir çekirdek bulunmaz. Kalıtım maddesi (DNA) sitoplazmada serbest bulunur. Bakteriler bu gruba girer."},{"t":"Ökaryot hücre","a":"Çekirdeği var","d":"Ökaryot hücrelerde zarla çevrili gerçek bir çekirdek bulunur. DNA bu çekirdeğin içinde korunur. Bitki ve hayvan hücreleri ökaryottur."},{"t":"Temel ayrım","a":"Çekirdek zarı","d":"İki hücre tipini ayıran en temel özellik çekirdek zarının olup olmamasıdır. Prokaryotta çekirdek zarı yokken ökaryotta vardır. Bu yüzden DNA prokaryotta serbest, ökaryotta korunaklıdır."}],"ans":"Temel ayrım çekirdek zarıdır: prokaryotta gerçek çekirdek yokken ökaryotta zarla çevrili çekirdek bulunur."},{"q":"Bakteri DNA'sı hangi şekildedir?","steps":[{"t":"Bakteri yapısı","a":"Prokaryot hücre","d":"Bakteriler prokaryot hücrelerdir. Çekirdekleri olmadığı için DNA serbest hâldedir. DNA'nın şekli ökaryot hücrelerden farklıdır."},{"t":"DNA şekli","a":"Halkasal","d":"Bakteri DNA'sı halka biçimindedir, yani uçları birbirine bağlıdır. Bu yapıya halkasal DNA denir. Ökaryot hücrelerdeki DNA ise doğrusal biçimdedir."}],"ans":"Bakteri DNA'sı halkasal (halka biçiminde) yapıdadır."},{"q":"Zarlı organeller hangi hücre tipinde bulunur?","steps":[{"t":"Zarlı organel nedir?","a":"Zarla çevrili bölüm","d":"Organeller hücre içindeki küçük görevli bölümlerdir. Bazıları çevresinde zar bulundurur, bunlara zarlı organel denir. Mitokondri buna örnektir."},{"t":"Hangi hücrede?","a":"Ökaryotta","d":"Zarlı organeller yalnızca ökaryot hücrelerde bulunur. Prokaryot hücrelerde zarlı organel yoktur. Bu da iki hücre tipi arasındaki farklardan biridir."}],"ans":"Zarlı organeller yalnızca ökaryot hücrelerde bulunur; prokaryot hücrelerde yoktur."},{"q":"İnsan ve bakteri hücresinden hangisi daha büyüktür?","steps":[{"t":"Hücre boyutları","a":"Farklı büyüklük","d":"Prokaryot ve ökaryot hücreler farklı büyüklüktedir. Prokaryot hücreler genelde çok küçüktür. Ökaryot hücreler ise belirgin biçimde daha büyüktür."},{"t":"Karşılaştırma","a":"İnsan hücresi büyük","d":"İnsan hücresi ökaryot olduğu için bakteriden çok daha büyüktür. Bir insan hücresi, bir bakterinin onlarca katı olabilir. Yani insan hücresi daha büyüktür."}],"ans":"İnsan hücresi (ökaryot) bakteri hücresinden (prokaryot) belirgin biçimde daha büyüktür."},{"q":"Bakteriler hangi hücre grubuna girer?","steps":[{"t":"Bakterinin özelliği","a":"Çekirdeksiz","d":"Bakterilerde gerçek çekirdek ve zarlı organel bulunmaz. DNA'ları sitoplazmada serbest durur. Yapıları nispeten basittir."},{"t":"Grup adı","a":"Prokaryot grubu","d":"Çekirdeksiz, zarlı organelsiz hücrelere prokaryot denir. Bakteriler bu grubun tipik örneğidir. Bu nedenle bakteriler prokaryot canlılardır."}],"ans":"Bakteriler prokaryot hücre grubuna girer."}],"zor":[{"q":"Mitokondri prokaryot bir hücrede bulunabilir mi? Açıklayınız.","steps":[{"t":"Mitokondri nedir?","a":"Zarlı organel","d":"Mitokondri çift zarlı bir organeldir ve hücreye enerji sağlar. Çevresinde zar bulunduğu için zarlı organel sınıfındadır. Bu yapı oldukça gelişmiştir."},{"t":"Prokaryotta zarlı organel?","a":"Bulunmaz","d":"Prokaryot hücrelerde zarla çevrili organeller bulunmaz. Bu hücreler yalnızca ribozom gibi zarsız yapılara sahiptir. Mitokondri ise zarlı bir organeldir."},{"t":"Sonuç","a":"Bulunamaz","d":"Mitokondri zarlı bir organel olduğundan prokaryot hücrede yer alamaz. Prokaryotlar enerji üretimini hücre zarları ve sitoplazmaları ile yapar. Dolayısıyla mitokondri yalnızca ökaryot hücrelerde bulunur."}],"ans":"Hayır; mitokondri zarlı bir organel olduğundan, zarlı organel içermeyen prokaryot hücrelerde bulunamaz."},{"q":"Bir hücrede halkasal DNA görülürse bu hücre hakkında ne söylenebilir?","steps":[{"t":"Halkasal DNA özelliği","a":"Prokaryota özgü","d":"Halkasal DNA, uçları kapalı halka biçimindeki kalıtım maddesidir. Bu yapı tipik olarak prokaryot hücrelerde görülür. Ökaryot çekirdeğindeki DNA ise doğrusaldır."},{"t":"Çekirdek durumu","a":"Çekirdek yok","d":"Halkasal DNA sitoplazmada serbest bulunur. Bu durum hücrede gerçek bir çekirdek olmadığını gösterir. Çünkü ökaryotta DNA çekirdek içinde korunur."},{"t":"Sonuç","a":"Prokaryottur","d":"Halkasal DNA ve çekirdek yokluğu hücrenin prokaryot olduğunu gösterir. Bu özelliklere sahip canlılara bakteriler örnektir. Dolayısıyla hücre prokaryottur."}],"ans":"Halkasal DNA, çekirdeği olmayan prokaryot bir hücreyi (örneğin bir bakteriyi) gösterir."},{"q":"Hem prokaryot hem ökaryot hücrede ortak olarak bulunan üç yapı nedir?","steps":[{"t":"Ortak yapıları arayalım","a":"Tüm hücrelerde var","d":"Bazı yapılar bütün hücrelerde temel olarak bulunur. Bunlar hücrenin yaşaması için gereklidir. Hem prokaryot hem ökaryotta görülürler."},{"t":"Hangileri ortak?","a":"Zar, sitoplazma, ribozom","d":"Hücre zarı dışarıyla sınır oluşturur ve her hücrede bulunur. Sitoplazma hücreyi dolduran sıvıdır. Ribozom ise protein üreten zarsız yapıdır ve her iki hücrede de vardır."},{"t":"Sonuç","a":"Üç ortak yapı","d":"Hücre zarı, sitoplazma ve ribozom her iki hücre tipinde ortaktır. DNA da her ikisinde bulunur ama şekilleri farklıdır. Bu ortak yapılar temel yaşamsal görevleri yürütür."}],"ans":"Hücre zarı, sitoplazma ve ribozom hem prokaryot hem ökaryot hücrede ortaktır."},{"q":"Ökaryot hücrelerin prokaryotlardan daha karmaşık olmasının nedeni nedir?","steps":[{"t":"Prokaryot yapısı","a":"Basit","d":"Prokaryot hücrelerde çekirdek ve zarlı organel bulunmaz. Az sayıda yapı içerirler. Bu nedenle yapıları nispeten basittir."},{"t":"Ökaryot yapısı","a":"Çok bölmeli","d":"Ökaryot hücrelerde çekirdek ve çok sayıda zarlı organel bulunur. Her organelin ayrı bir görevi vardır. Bu bölmeli yapı işleri ayrı odalarda yürütmeyi sağlar."},{"t":"Sonuç","a":"Bölmelenme","d":"Ökaryot hücredeki çekirdek ve zarlı organeller hücreyi bölmelere ayırır. Bu bölmelenme daha fazla iş bölümü ve düzen sağlar. Bu nedenle ökaryotlar daha karmaşıktır."}],"ans":"Ökaryotlarda çekirdek ve zarlı organellerin oluşturduğu bölmelenme nedeniyle yapı daha karmaşıktır."},{"q":"Bir öğrenci mikroskopta çekirdeği belirgin, içinde mitokondri olan bir hücre görüyor. Bu hücre prokaryot mu ökaryot mu?","steps":[{"t":"Çekirdek ipucu","a":"Belirgin çekirdek","d":"Hücrede belirgin, zarla çevrili bir çekirdek görülmektedir. Gerçek çekirdek yalnızca ökaryot hücrelerde bulunur. Bu ilk önemli ipucudur."},{"t":"Organel ipucu","a":"Mitokondri var","d":"Hücrede mitokondri gözlenmektedir. Mitokondri zarlı bir organeldir. Zarlı organeller sadece ökaryot hücrelerde yer alır."},{"t":"Sonuç","a":"Ökaryottur","d":"Hem belirgin çekirdek hem de mitokondri varlığı ökaryotu işaret eder. Prokaryotlarda bu yapıların ikisi de bulunmaz. Dolayısıyla bu hücre ökaryottur."}],"ans":"Belirgin çekirdek ve mitokondri içerdiği için bu hücre ökaryottur."}]},"lise":{"kolay":[{"q":"Prokaryot hücrede DNA neden bir zarla korunmaz?","steps":[{"t":"Çekirdek zarının yokluğu","a":"Gerçek çekirdek yok","d":"Prokaryot hücrelerde zarla çevrili gerçek bir çekirdek bulunmaz. Bu nedenle DNA'yı çevreleyecek bir çekirdek zarı da yoktur. Kalıtım maddesini ayrı tutan bir bölme oluşmamıştır."},{"t":"DNA'nın konumu","a":"Sitoplazmada","d":"Prokaryotta DNA, sitoplazma içinde nükleoid adı verilen düzensiz bir bölgede bulunur. Bu bölge bir zarla sınırlanmamıştır. DNA böylece sitoplazmadaki yapılarla doğrudan temas hâlindedir."},{"t":"Sonuç","a":"Zarsız korunma","d":"Çekirdek zarı olmadığı için DNA bir zarla korunmaz. Bunun yerine sitoplazmada serbest hâlde bulunur. Bu durum prokaryot hücrelerin temel özelliğidir."}],"ans":"Prokaryotta çekirdek zarı bulunmadığından DNA sitoplazmada nükleoid bölgesinde zarsız, serbest hâlde bulunur."},{"q":"Ökaryot kelimesi ne anlama gelir ve hangi canlıları kapsar?","steps":[{"t":"Kelime anlamı","a":"Gerçek çekirdek","d":"Ökaryot sözcüğü gerçek çekirdekli anlamına gelir. Bu canlıların hücrelerinde zarla çevrili çekirdek bulunur. Çekirdek, kalıtım maddesini korur."},{"t":"Kapsadığı canlılar","a":"Bitki, hayvan, mantar, protista","d":"Ökaryotlar bitkileri, hayvanları, mantarları ve protistaları kapsar. Bu canlıların hepsinde gerçek çekirdek bulunur. Hepsinde zarlı organeller de yer alır."}],"ans":"Ökaryot gerçek çekirdekli demektir; bitkileri, hayvanları, mantarları ve protistaları kapsar."},{"q":"Ribozom hem prokaryot hem ökaryotta bulunduğuna göre ribozomun ortak özelliği nedir?","steps":[{"t":"Ribozomun yapısı","a":"Zarsız organel","d":"Ribozom protein üretiminden sorumlu küçük bir yapıdır. Etrafında zar bulunmaz, yani zarsız bir organeldir. Bu özellik onu zarlı organellerden ayırır."},{"t":"Neden her hücrede var?","a":"Protein her hücrede gerekli","d":"Protein sentezi her hücre için zorunlu bir yaşamsal işlevdir. Bu nedenle ribozom hem prokaryot hem ökaryotta bulunur. Zarsız olduğundan prokaryotta da yer alabilir."}],"ans":"Ribozom zarsız bir organeldir ve protein sentezi her hücrede gerekli olduğundan hem prokaryot hem ökaryotta bulunur."},{"q":"Bakteri hücresinde bulunan hücre duvarı ile bitki hücresindeki hücre duvarı aynı maddeden mi yapılır?","steps":[{"t":"Bakteri hücre duvarı","a":"Peptidoglikan","d":"Bakteri hücre duvarının ana yapı maddesi peptidoglikandır. Bu madde bakteriye özgüdür. Hücreye dayanıklılık ve şekil kazandırır."},{"t":"Bitki hücre duvarı","a":"Selüloz","d":"Bitki hücre duvarının ana yapı maddesi selülozdur. Selüloz bir karbonhidrat çeşididir. Bitkiye desteklik ve dayanıklılık sağlar."},{"t":"Karşılaştırma","a":"Farklı maddeler","d":"Bakteri duvarı peptidoglikandan, bitki duvarı selülozdan yapılır. Yani ikisinin yapı maddesi farklıdır. İşlevleri benzese de bileşimleri ayrıdır."}],"ans":"Hayır; bakteri hücre duvarı peptidoglikandan, bitki hücre duvarı selülozdan yapılır."},{"q":"Prokaryot hücrelerin tipik boyutu ile ökaryot hücrelerin boyutu nasıl karşılaştırılır?","steps":[{"t":"Prokaryot boyutu","a":"1-10 mikrometre","d":"Prokaryot hücreler genellikle 1 ile 10 mikrometre arasında bir boyuttadır. Bu nedenle oldukça küçüktürler. Yapıları da basit olduğundan az yer kaplarlar."},{"t":"Ökaryot boyutu","a":"10-100 mikrometre","d":"Ökaryot hücreler genellikle 10 ile 100 mikrometre arasında değişir. Bu da onları prokaryotlardan daha büyük yapar. İçlerinde çok sayıda organel bulunur."},{"t":"Sonuç","a":"Ökaryot daha büyük","d":"Sayılar karşılaştırıldığında ökaryot hücrenin daha büyük olduğu görülür. Ökaryotlar prokaryotların yaklaşık on katı büyüklükte olabilir. Bu boyut farkı içerdikleri organellerle ilgilidir."}],"ans":"Prokaryotlar tipik olarak 1-10 mikrometre, ökaryotlar 10-100 mikrometredir; ökaryotlar belirgin biçimde daha büyüktür."},{"q":"Nükleoid bölgesi nedir ve hangi hücrede bulunur?","steps":[{"t":"Nükleoid tanımı","a":"DNA'nın yoğunlaştığı bölge","d":"Nükleoid, prokaryot hücrede DNA'nın toplandığı düzensiz bölgedir. Bu bölgenin etrafında zar bulunmaz. Burası gerçek bir çekirdek değildir."},{"t":"Hangi hücrede?","a":"Prokaryotta","d":"Nükleoid yalnızca prokaryot hücrelerde görülür. Çünkü ökaryotlarda DNA zarla çevrili çekirdekte bulunur. Prokaryotta ise böyle bir zar olmadığından DNA nükleoidde toplanır."}],"ans":"Nükleoid, prokaryot hücrede DNA'nın yoğunlaştığı zarsız bölgedir."},{"q":"Ökaryot hücrede bulunup prokaryotta bulunmayan iki organel söyleyiniz.","steps":[{"t":"Zarlı organel ölçütü","a":"Zarlı yapılar","d":"Prokaryot hücrelerde zarla çevrili organeller bulunmaz. Bu nedenle yalnızca zarlı olan organeller ökaryota özgüdür. Zarsız ribozom ise her ikisinde vardır."},{"t":"Örnek organeller","a":"Mitokondri, çekirdek","d":"Mitokondri çift zarlı bir organel olup yalnızca ökaryotta bulunur. Gerçek çekirdek de zarla çevrilidir ve sadece ökaryotta yer alır. Bu iki yapı prokaryotta yoktur."}],"ans":"Mitokondri ve gerçek çekirdek ökaryotta bulunur, prokaryotta bulunmaz."},{"q":"Mavi-yeşil algler (siyanobakteriler) prokaryot mudur?","steps":[{"t":"Siyanobakteri özelliği","a":"Bakteri grubu","d":"Siyanobakteriler fotosentez yapabilen bir bakteri grubudur. Yapıları diğer bakteriler gibidir. İçlerinde gerçek çekirdek bulunmaz."},{"t":"Sınıflandırma","a":"Prokaryot","d":"Çekirdeksiz ve zarlı organelsiz olduklarından siyanobakteriler prokaryottur. Fotosentez yapmaları onları ökaryot yapmaz. Klorofilleri sitoplazmaya dağılmış hâldedir."}],"ans":"Evet; siyanobakteriler çekirdeksiz oldukları için prokaryottur."},{"q":"Prokaryot hücrelerde protein sentezi nasıl gerçekleşir?","steps":[{"t":"Gerekli yapı","a":"Ribozom","d":"Protein sentezi için ribozom adı verilen organel gereklidir. Ribozom zarsız bir yapıdır. Prokaryot hücreler de ribozoma sahiptir."},{"t":"Nerede gerçekleşir?","a":"Sitoplazmada","d":"Prokaryotta ribozomlar sitoplazmada serbest hâlde bulunur. Protein sentezi de doğrudan sitoplazmada gerçekleşir. Çekirdek zarı olmadığından DNA ile ribozom aynı ortamda bulunur."}],"ans":"Prokaryotlarda protein sentezi sitoplazmadaki serbest ribozomlarda gerçekleşir."},{"q":"Ökaryot hücrede DNA'nın doğrusal olması neyi mümkün kılar?","steps":[{"t":"Doğrusal DNA","a":"Uçları açık","d":"Ökaryot DNA'sı uçları açık, doğrusal iplikler hâlindedir. Bu iplikler proteinlerle sarılarak kromozomları oluşturur. Halkasal DNA'dan farklı bir düzenlenme sağlar."},{"t":"Avantajı","a":"Çok DNA paketlenir","d":"Doğrusal yapı, çok miktarda DNA'nın kromozomlar hâlinde düzenli paketlenmesini sağlar. Böylece büyük bir genetik bilgi sığdırılabilir. Bu da ökaryotların daha çok gen taşımasını mümkün kılar."}],"ans":"Doğrusal DNA, ökaryotlarda büyük miktarda kalıtım maddesinin kromozomlar hâlinde düzenli paketlenmesini sağlar."},{"q":"Bir hücrede kloroplast görülmesi onun prokaryot olmadığını gösterir mi?","steps":[{"t":"Kloroplast yapısı","a":"Zarlı organel","d":"Kloroplast fotosentezden sorumlu çift zarlı bir organeldir. Çevresinde zar bulunduğu için zarlı organeldir. Oldukça gelişmiş bir yapıya sahiptir."},{"t":"Prokaryotta zarlı organel?","a":"Yok","d":"Prokaryot hücrelerde zarlı organeller bulunmaz. Kloroplast da zarlı bir organel olduğundan prokaryotta yer alamaz. Dolayısıyla kloroplast varlığı prokaryotu dışlar."},{"t":"Sonuç","a":"Ökaryottur","d":"Kloroplast görülen bir hücre kesinlikle ökaryottur. Bu hücre büyük olasılıkla bir bitki ya da algdir. Yani prokaryot değildir."}],"ans":"Evet; kloroplast zarlı bir organel olduğundan, onu içeren hücre prokaryot değil ökaryottur."},{"q":"Prokaryotlar Dünya üzerinde ökaryotlardan önce mi yoksa sonra mı ortaya çıkmıştır?","steps":[{"t":"Yapı karmaşıklığı","a":"Prokaryot basit","d":"Prokaryot hücreler basit yapılıdır ve az sayıda parça içerir. Ökaryotlar ise daha karmaşık ve bölmeli yapıdadır. Genellikle basit yapılar önce ortaya çıkar."},{"t":"Sonuç","a":"Prokaryot önce","d":"Bilimsel veriler prokaryotların Dünya tarihinde önce ortaya çıktığını gösterir. Ökaryotlar daha sonra ve daha karmaşık yapıyla görülmüştür. Yani prokaryotlar daha eskidir."}],"ans":"Prokaryotlar, daha basit yapılı oldukları için ökaryotlardan önce ortaya çıkmıştır."},{"q":"Hücre zarı hem prokaryot hem ökaryotta bulunur; bu yapının ortak görevi nedir?","steps":[{"t":"Hücre zarının yapısı","a":"Seçici geçirgen","d":"Hücre zarı, hücreyi dış ortamdan ayıran ince bir tabakadır. Madde geçişini denetleyen seçici geçirgen bir yapıdır. Hem prokaryot hem ökaryotta bulunur."},{"t":"Ortak görevi","a":"Madde alışverişi","d":"Hücre zarı her iki hücre tipinde de madde alışverişini düzenler. Hangi maddenin gireceğine ve çıkacağına karar verir. Böylece hücre içi dengeyi korur."}],"ans":"Hücre zarının ortak görevi, seçici geçirgenliği ile madde alışverişini düzenleyip hücre içi dengeyi korumaktır."},{"q":"Bakterilerde bulunan plazmit nedir?","steps":[{"t":"Plazmit tanımı","a":"Küçük halkasal DNA","d":"Plazmit, bakterilerde ana DNA dışında bulunan küçük, halkasal bir DNA parçasıdır. Ana kromozomdan bağımsız çoğalabilir. Üzerinde bazı ek genler taşır."},{"t":"Önemi","a":"Ek özellik kazandırır","d":"Plazmitler bakteriye ek özellikler kazandırabilir, örneğin bazı maddelere karşı direnç. Bu genler bakterinin yaşamını kolaylaştırabilir. Plazmit yalnızca prokaryotlarda görülen bir yapıdır."}],"ans":"Plazmit, bakterilerde ana DNA dışında bulunan ve ek genler taşıyan küçük halkasal DNA parçasıdır."},{"q":"Prokaryot bir hücrede zarla bölmelenme olmamasının protein sentezine etkisi nedir?","steps":[{"t":"Bölmelenme yokluğu","a":"DNA ve ribozom bir arada","d":"Prokaryotta çekirdek zarı olmadığından DNA ve ribozomlar aynı ortamda bulunur. Yani sitoplazma tek bir bölmedir. Yapılar arasında zar engeli yoktur."},{"t":"Etkisi","a":"Eş zamanlı sentez","d":"DNA'dan bilgi okunurken ribozom hemen yanında protein üretebilir. Bu sayede süreçler eş zamanlı yürüyebilir. Bölmelenme olmadığı için aşamalar birbirini hızla izler."}],"ans":"Bölmelenme olmadığından prokaryotta DNA'dan bilginin okunması ile protein sentezi aynı ortamda, eş zamanlı yürüyebilir."}],"zor":[{"q":"Endosimbiyoz kuramına göre mitokondri ve kloroplastın prokaryot kökenli olduğu hangi kanıtlarla açıklanır?","steps":[{"t":"Kuramın özü","a":"Hücre içine alınma","d":"Endosimbiyoz kuramına göre, eski bir ökaryot hücre küçük prokaryot hücreleri içine almıştır. Bu prokaryotlar zamanla mitokondri ve kloroplasta dönüşmüştür. Yani bu organeller bir zamanlar bağımsız bakterilerdi."},{"t":"Birinci kanıt","a":"Kendi DNA'sı","d":"Mitokondri ve kloroplastın kendilerine ait halkasal DNA'sı vardır. Bu DNA prokaryotlardaki gibi halkasaldır. Bu durum onların bakteri kökenli olduğunu destekler."},{"t":"İkinci kanıt","a":"Kendi ribozomu ve çift zarı","d":"Bu organeller kendi ribozomlarına sahiptir ve bunlar bakteri ribozomlarına benzer. Ayrıca çift zarlıdırlar; dış zar konak hücreden, iç zar bakteriden gelmiş gibidir. Kendi başlarına bölünebilmeleri de bu kuramı güçlendirir."},{"t":"Sonuç","a":"Prokaryot kökeni","d":"Halkasal DNA, bakteri benzeri ribozom, çift zar ve bağımsız bölünme birlikte değerlendirildiğinde organellerin prokaryot kökenli olduğu sonucuna varılır. Bu kanıtlar endosimbiyoz kuramını destekler. Böylece ökaryot hücrelerin oluşumu açıklanır."}],"ans":"Kendi halkasal DNA'ları, bakteri benzeri ribozomları, çift zarları ve bağımsız bölünebilmeleri mitokondri ile kloroplastın prokaryot kökenli olduğunu gösterir."},{"q":"Bir antibiyotik yalnızca bakteri ribozomlarını engelliyor; bu nasıl seçici etki sağlar?","steps":[{"t":"Ribozom farkı","a":"Boyut farklı","d":"Prokaryot ve ökaryot ribozomları farklı büyüklük ve yapıdadır. Bakteri ribozomu insan ribozomundan farklı bir biçime sahiptir. Bu fark moleküler düzeyde belirgindir."},{"t":"Antibiyotiğin hedefi","a":"Sadece bakteri ribozomu","d":"Antibiyotik yalnızca bakteri tipi ribozoma bağlanacak şekilde davranabilir. İnsan ribozomuna bağlanmaz çünkü yapısı farklıdır. Böylece sadece bakteride protein sentezini durdurur."},{"t":"Seçici etki","a":"İnsan hücresi zarar görmez","d":"Bakteride protein üretimi durunca bakteri çoğalamaz ve ölür. İnsan hücreleri ise farklı ribozoma sahip olduğundan etkilenmez. Bu sayede antibiyotik seçici, yani sadece bakteriye zarar veren bir etki gösterir."}],"ans":"Bakteri ve insan ribozomları yapıca farklı olduğundan, yalnızca bakteri ribozomuna bağlanan antibiyotik sadece bakteriyi etkiler, insan hücresine zarar vermez."},{"q":"Prokaryotların yüzey/hacim oranı, büyük ökaryotlardan neden daha avantajlıdır?","steps":[{"t":"Yüzey/hacim ilişkisi","a":"Küçük hücre avantajlı","d":"Bir hücre küçüldükçe yüzey alanının hacme oranı artar. Madde alışverişi hücre yüzeyinden olur. Büyük yüzey/hacim oranı daha hızlı madde geçişi demektir."},{"t":"Prokaryotun durumu","a":"Çok küçük","d":"Prokaryotlar çok küçük olduğundan yüzey/hacim oranları yüksektir. Bu da madde alışverişini hızlandırır. Hücrenin her noktasına besin kolayca ulaşır."},{"t":"Ökaryotun durumu","a":"Büyük, oran düşük","d":"Büyük ökaryot hücrelerde yüzey/hacim oranı düşüktür. Bu nedenle madde geçişi daha yavaş olabilir. Ökaryotlar bu sorunu organeller ve iç zarlarla çözer."},{"t":"Sonuç","a":"Hızlı alışveriş","d":"Yüksek yüzey/hacim oranı prokaryota hızlı madde alışverişi ve hızlı üreme avantajı sağlar. Küçük boyut bu nedenle elverişlidir. Büyük ökaryotlar ise iç düzenlemelerle bu dezavantajı dengeler."}],"ans":"Çok küçük oldukları için prokaryotların yüzey/hacim oranı yüksektir; bu da hızlı madde alışverişi ve hızlı üreme avantajı sağlar."},{"q":"Prokaryotta operon düzeni protein sentezini nasıl etkiler?","steps":[{"t":"Operon nedir?","a":"Birlikte yönetilen genler","d":"Operon, prokaryotta birbiriyle ilişkili genlerin tek bir denetim altında toplandığı düzendir. Bu genler birlikte açılıp kapanır. Genellikle aynı işe yarayan proteinleri kodlar."},{"t":"Avantajı","a":"Toplu üretim","d":"Operon sayesinde birden çok protein aynı anda ve birlikte üretilebilir. Hücre bir işi yapacaksa gereken tüm proteinleri eş zamanlı sentezler. Bu, enerji ve zaman açısından verimlidir."},{"t":"Ökaryotla fark","a":"Ökaryotta yok","d":"Ökaryotlarda genler genelde ayrı ayrı yönetilir, operon düzeni tipik değildir. Bu yüzden prokaryottaki toplu denetim ökaryota göre bir farktır. Operon, prokaryotun hızlı uyum sağlamasını kolaylaştırır."}],"ans":"Operon, ilişkili genleri birlikte yöneterek birden çok proteinin eş zamanlı ve verimli üretilmesini sağlar; bu düzen ökaryotlarda tipik değildir."},{"q":"Çekirdek zarının varlığı ökaryotta transkripsiyon ve translasyonu nasıl ayırır?","steps":[{"t":"Çekirdek zarının rolü","a":"Bölme oluşturur","d":"Ökaryotta çekirdek zarı, DNA'yı sitoplazmadan ayıran bir sınır oluşturur. Böylece çekirdek ile sitoplazma iki ayrı bölme hâline gelir. Bu bölmelenme süreçleri yer bakımından ayırır."},{"t":"Transkripsiyon yeri","a":"Çekirdekte","d":"DNA'dan bilginin RNA'ya yazılması, yani transkripsiyon çekirdek içinde gerçekleşir. Çünkü DNA çekirdekte korunur. Üretilen RNA daha sonra sitoplazmaya geçer."},{"t":"Translasyon yeri","a":"Sitoplazmada","d":"Proteinin üretilmesi, yani translasyon sitoplazmadaki ribozomlarda olur. RNA çekirdekten çıkıp sitoplazmaya ulaştıktan sonra bu işlem başlar. Böylece iki süreç farklı yerlerde gerçekleşir."},{"t":"Sonuç","a":"Mekânsal ayrım","d":"Çekirdek zarı, transkripsiyonu çekirdeğe, translasyonu sitoplazmaya hapseder. Bu ayrım prokaryotta yoktur; orada ikisi aynı ortamda olur. Ökaryottaki bu ayrım daha düzenli bir denetim sağlar."}],"ans":"Çekirdek zarı, transkripsiyonu çekirdekte, translasyonu sitoplazmada gerçekleştirerek iki süreci mekânsal olarak ayırır; prokaryotta bu ayrım yoktur."},{"q":"Arkeler bakterilere benzer ama bazı yönlerden ökaryotlara yakındır; bu durumu prokaryot kavramı içinde nasıl açıklarız?","steps":[{"t":"Arkelerin yapısı","a":"Çekirdeksiz","d":"Arkeler de bakteriler gibi çekirdeksiz, zarlı organelsiz hücrelerdir. Yapısal olarak prokaryot sayılırlar. Halkasal DNA'ya sahiptirler."},{"t":"Ökaryota benzerlik","a":"Bazı moleküller","d":"Arkelerin bazı proteinleri ve gen okuma mekanizmaları ökaryotlara benzer. Bu nedenle tamamen bakteri gibi değildirler. Hücre zarı yapıları da farklıdır."},{"t":"Sonuç","a":"Ayrı bir prokaryot grup","d":"Arkeler çekirdeksiz oldukları için prokaryot kategorisindedir. Ancak bakterilerden ayrı bir grup sayılırlar. Yani prokaryot olmak tek tip canlı demek değildir; bakteriler ve arkeler iki ayrı prokaryot koldur."}],"ans":"Arkeler çekirdeksiz oldukları için prokaryottur, fakat bazı moleküler özellikleri ökaryota benzediğinden bakterilerden ayrı bir prokaryot grup olarak değerlendirilir."},{"q":"Bir hücrenin prokaryot mu ökaryot mu olduğunu belirlemek için izlenecek mantıksal sıra nasıl olmalıdır?","steps":[{"t":"İlk ölçüt","a":"Çekirdek zarı","d":"İlk bakılacak özellik zarla çevrili gerçek çekirdeğin varlığıdır. Çekirdek zarı varsa hücre ökaryottur. Yoksa diğer ölçütlere bakılır."},{"t":"İkinci ölçüt","a":"Zarlı organel","d":"Çekirdek belirsizse zarlı organellerin varlığı kontrol edilir. Mitokondri, kloroplast gibi zarlı organeller varsa hücre ökaryottur. Bunlar yoksa prokaryot olasılığı güçlenir."},{"t":"Üçüncü ölçüt","a":"DNA şekli ve boyut","d":"Halkasal DNA ve küçük boyut prokaryotu işaret eder. Doğrusal DNA ve büyük boyut ise ökaryotu gösterir. Bu ölçütler kararı netleştirir."},{"t":"Sonuç","a":"Mantıksal karar","d":"Çekirdek zarı, zarlı organel, DNA şekli ve boyut sırasıyla değerlendirilir. Bu özellikler birlikte hücre tipini kesinleştirir. Böylece sağlıklı bir sınıflandırma yapılır."}],"ans":"Önce çekirdek zarına, sonra zarlı organellere, ardından DNA şekli ve hücre boyutuna bakılarak hücrenin prokaryot mu ökaryot mu olduğu belirlenir."},{"q":"Prokaryotik bir hücre çok kısa sürede çoğalabilirken büyük ökaryot hücreler neden daha yavaş çoğalır?","steps":[{"t":"Prokaryotun bölünmesi","a":"Basit ikiye bölünme","d":"Prokaryotlar ikiye bölünme adı verilen basit bir yolla çoğalır. Tek halkasal DNA kopyalanır ve hücre ikiye ayrılır. Az yapı içerdiğinden bu süreç hızlıdır."},{"t":"Ökaryotun bölünmesi","a":"Karmaşık mitoz","d":"Ökaryotlar mitoz gibi düzenli ve aşamalı bir bölünme geçirir. Çok sayıda kromozom ve organel kopyalanıp paylaştırılır. Bu da süreci uzatır."},{"t":"Sonuç","a":"Prokaryot daha hızlı","d":"Az yapı ve basit bölünme prokaryota hız kazandırır. Çok organel ve karmaşık bölünme ökaryotu yavaşlatır. Bu nedenle prokaryotlar çok daha kısa sürede çoğalabilir."}],"ans":"Prokaryotlar basit ikiye bölünmeyle hızlı çoğalırken, çok kromozom ve organel taşıyan ökaryotlar karmaşık mitoz nedeniyle daha yavaş çoğalır."},{"q":"Hücre zarı her iki hücrede ortak olsa da, prokaryot ve ökaryot zarlarının görev yükü neden farklıdır?","steps":[{"t":"Prokaryot zarı","a":"Çok görevli","d":"Prokaryotta zarlı organel olmadığından birçok iş hücre zarında yürür. Enerji üretimi ve bazı tepkimeler doğrudan zar üzerinde gerçekleşebilir. Yani zar ek görevler üstlenir."},{"t":"Ökaryot zarı","a":"Görev paylaşımı","d":"Ökaryotta enerji üretimi gibi işler mitokondri ve diğer organellere devredilmiştir. Bu nedenle hücre zarının yükü azalır. Zar daha çok madde alışverişiyle ilgilenir."},{"t":"Sonuç","a":"Yük dağılımı farkı","d":"Prokaryot zarı hem sınır hem üretim yeri olarak çok yönlü çalışır. Ökaryotta ise bu görevler organellere bölünmüştür. Bu yüzden iki zarın görev yükü farklıdır."}],"ans":"Prokaryotta organel olmadığından hücre zarı enerji üretimi gibi ek görevler üstlenir; ökaryotta bu görevler organellere devredildiğinden zarın yükü azalır."},{"q":"Genetik mühendisliğinde bakterilerin tercih edilmesinin prokaryot yapısıyla ilişkisini açıklayınız.","steps":[{"t":"Plazmit avantajı","a":"Kolay gen aktarımı","d":"Bakterilerde bulunan plazmitler küçük halkasal DNA parçalarıdır. Bunlara dışarıdan gen eklemek ve geri vermek kolaydır. Bu, gen aktarımını pratik hâle getirir."},{"t":"Hızlı çoğalma","a":"Kısa sürede çok kopya","d":"Bakteriler çok hızlı çoğaldığından kısa sürede milyonlarca kopya elde edilir. İstenen gen bu kopyalarda bol miktarda üretilir. Bu da verimi artırır."},{"t":"Basit yapı","a":"Yönetimi kolay","d":"Prokaryot yapısı basit olduğundan bakterilerle çalışmak ucuz ve kolaydır. Az organel ve basit denetim sistemleri işlemi sadeleştirir. Bu nedenle bakteriler tercih edilir."},{"t":"Sonuç","a":"İdeal araç","d":"Plazmit, hızlı çoğalma ve basit yapı bir araya gelince bakteriler ideal birer üretim aracı olur. İstenen protein bol ve ucuz üretilebilir. Bu yüzden genetik mühendisliğinde sıkça kullanılırlar."}],"ans":"Plazmitleriyle kolay gen aktarımı, hızlı çoğalmaları ve basit prokaryot yapıları sayesinde bakteriler, istenen geni ucuz ve bol üretmek için genetik mühendisliğinde tercih edilir."},{"q":"Bir hücrede DNA hem halkasal hem de zarsız bulunuyor, ayrıca ribozom var ama mitokondri yok. Bu hücreyi sınıflandırıp gerekçelendiriniz.","steps":[{"t":"DNA özelliği","a":"Halkasal ve zarsız","d":"Hücredeki DNA halka biçiminde ve zarla çevrili değildir. Halkasal, zarsız DNA prokaryotun belirgin özelliğidir. Bu ilk güçlü ipucudur."},{"t":"Organel durumu","a":"Mitokondri yok","d":"Hücrede mitokondri gibi zarlı organel bulunmamaktadır. Zarlı organel yokluğu da prokaryotu destekler. Yalnızca zarsız ribozomun olması bununla uyumludur."},{"t":"Ribozom varlığı","a":"Çelişki değil","d":"Ribozom hem prokaryot hem ökaryotta bulunduğu için ayırt edici değildir. Burada ribozom varlığı prokaryot olmasına engel oluşturmaz. Zarsız olduğundan prokaryotta da yer alabilir."},{"t":"Sonuç","a":"Prokaryottur","d":"Halkasal zarsız DNA ve zarlı organel yokluğu hücrenin prokaryot olduğunu gösterir. Ribozomun varlığı bu sonucu bozmaz. Dolayısıyla bu hücre bir prokaryottur, büyük olasılıkla bakteridir."}],"ans":"Halkasal zarsız DNA ve zarlı organel (mitokondri) yokluğu nedeniyle hücre prokaryottur; ribozomun bulunması her iki tipte ortak olduğundan bu sonucu değiştirmez."},{"q":"Ökaryot hücrelerin bölmelenmiş yapısı, çelişen kimyasal tepkimeleri aynı anda yürütmeyi nasıl mümkün kılar?","steps":[{"t":"Bölmelenme nedir?","a":"Zarlı odalar","d":"Ökaryot hücre, zarlı organeller sayesinde içinde ayrı odalar barındırır. Her organel farklı bir kimyasal ortam sunar. Bu odalar birbirinden zarla ayrılır."},{"t":"Çelişen tepkimeler","a":"Yapım ve yıkım","d":"Bazı tepkimeler madde yapımı, bazıları madde yıkımı yönündedir. Bunlar aynı ortamda olsaydı birbirini engellerdi. Farklı koşullar gerektirdikleri için ayrılmaları gerekir."},{"t":"Bölmelenmenin çözümü","a":"Ayrı organeller","d":"Yapım bir organelde, yıkım başka bir organelde gerçekleşebilir. Böylece çelişen tepkimeler birbirine karışmaz. Her tepkime kendi uygun ortamında yürür."},{"t":"Sonuç","a":"Eş zamanlı çalışma","d":"Bölmelenme sayesinde zıt tepkimeler aynı anda ayrı yerlerde yürütülür. Bu, hücreye yüksek verim ve düzen sağlar. Prokaryotlar bu avantajdan büyük ölçüde yoksundur."}],"ans":"Zarlı organellerin oluşturduğu bölmelenme, çelişen tepkimeleri ayrı odalarda yürüterek aynı anda, birbirini engellemeden gerçekleşmelerini sağlar."},{"q":"Prokaryot ve ökaryot ribozomlarının büyüklük olarak farklı olması hangi yaşamsal sonucu doğurur?","steps":[{"t":"Ribozom büyüklüğü","a":"Prokaryot 70S, ökaryot 80S","d":"Prokaryot ribozomları 70S, ökaryot ribozomları 80S büyüklüğündedir. Bu sayılar ribozomun yapısal büyüklüğünü ifade eder. İki ribozom tipi yapı bakımından ayrılır."},{"t":"Yapısal fark","a":"Bağlanma bölgeleri farklı","d":"Büyüklük farkı, ilaçların bağlanabileceği bölgelerin de farklı olmasına yol açar. Bir madde bir ribozoma bağlanırken diğerine bağlanmayabilir. Bu, hücreler arasında seçicilik yaratır."},{"t":"Yaşamsal sonuç","a":"Seçici ilaç hedefi","d":"Bu fark sayesinde bazı antibiyotikler yalnızca 70S ribozomu hedefler. İnsan hücresinin 80S ribozomu etkilenmez. Böylece bakteriye zarar verirken insana zarar vermeyen ilaçlar üretilebilir."}],"ans":"Prokaryot (70S) ve ökaryot (80S) ribozomlarının büyüklük farkı, yalnızca bakteri ribozomunu hedefleyen seçici antibiyotiklerin geliştirilmesine olanak verir."},{"q":"Mitokondrinin kendi DNA'sının olması, ökaryot hücrenin çekirdek dışında da kalıtım taşıyabileceğini nasıl gösterir?","steps":[{"t":"Çekirdek DNA'sı","a":"Ana kalıtım","d":"Ökaryot hücrenin kalıtım maddesinin büyük kısmı çekirdekte bulunur. Bu DNA hücrenin pek çok özelliğini belirler. Ana yönetim merkezi çekirdektir."},{"t":"Mitokondri DNA'sı","a":"Ek halkasal DNA","d":"Mitokondrinin kendine ait küçük, halkasal bir DNA'sı vardır. Bu DNA mitokondrinin bazı proteinlerini kodlar. Yani çekirdek dışında da kalıtım maddesi bulunur."},{"t":"Anlamı","a":"Çekirdek dışı kalıtım","d":"Mitokondri DNA'sı, kalıtımın yalnızca çekirdekle sınırlı olmadığını gösterir. Bazı özellikler mitokondri yoluyla aktarılabilir. Bu durum endosimbiyoz kuramıyla da uyumludur."},{"t":"Sonuç","a":"İki kalıtım kaynağı","d":"Ökaryot hücrede hem çekirdek hem mitokondri kalıtım taşır. Bu, çekirdek dışı kalıtımın varlığını kanıtlar. Böylece kalıtımın kaynağı tek değildir."}],"ans":"Mitokondrinin kendi halkasal DNA'sı, ökaryot hücrede çekirdek dışında da kalıtım maddesi bulunduğunu, yani çekirdek dışı kalıtım olduğunu gösterir."},{"q":"Prokaryotların aşırı koşullarda yaşayabilmesi, basit yapılarıyla nasıl ilişkilendirilir?","steps":[{"t":"Aşırı koşullar","a":"Sıcak, tuzlu, asitli","d":"Bazı prokaryotlar çok sıcak, çok tuzlu veya çok asitli ortamlarda yaşayabilir. Bu ortamlar ökaryotlar için öldürücüdür. Buna rağmen bazı prokaryotlar burada üreyebilir."},{"t":"Basit yapının rolü","a":"Az hassas yapı","d":"Prokaryotlar az sayıda yapı içerir ve karmaşık organelleri yoktur. Bu nedenle hassas organellerin zarar görme riski düşüktür. Basit yapı, zorlu koşullara dayanmayı kolaylaştırır."},{"t":"Uyum yetenekleri","a":"Özel moleküller","d":"Bu prokaryotlar zorlu koşullara dayanıklı özel proteinler ve zar yapıları geliştirmiştir. Az sayıda yapı, bu uyumların korunmasını kolaylaştırır. Böylece aşırı ortamlarda hayatta kalırlar."},{"t":"Sonuç","a":"Dayanıklılık avantajı","d":"Basit yapı ve özel uyumlar prokaryotlara geniş yaşam alanı sağlar. Karmaşık ökaryotlar bu koşullara dayanamaz. Bu nedenle aşırı ortamlarda çoğunlukla prokaryotlar bulunur."}],"ans":"Az sayıda yapı içeren basit prokaryot hücreler, hassas organel taşımadıkları ve özel uyum molekülleri geliştirebildikleri için aşırı koşullara ökaryotlardan daha dayanıklıdır."}]}},"cekirdek":{"ilkokul":{"kolay":[{"q":"Hücrenin yönetim merkezi neresidir?","steps":[{"t":"Yönetim merkezi nedir?","a":"Hücreyi yöneten yer","d":"Hücrenin içinde her şeyi düzenleyen bir merkez bulunur. Bu merkez hücreye ne yapacağını söyler. Bir okulun müdürü gibi çalışır."},{"t":"Bu merkez nedir?","a":"Çekirdek","d":"Hücreyi yöneten merkeze çekirdek denir. Çekirdek hücrenin tam içinde bulunur. Hücrenin en önemli bölümlerinden biridir."}],"ans":"Hücrenin yönetim merkezi çekirdektir."},{"q":"Çekirdeğin içinde hücrenin bilgileri saklanır mı?","steps":[{"t":"Çekirdeğin görevi","a":"Bilgi saklamak","d":"Çekirdek hücreye ait önemli bilgileri korur. Bu bilgiler hücrenin nasıl çalışacağını anlatır. Çekirdek bir bilgi kutusu gibidir."},{"t":"Bilgi nerede?","a":"Çekirdekte","d":"Hücrenin bilgileri çekirdeğin içinde saklanır. Bu bilgilere DNA denir. Çekirdek bu bilgileri güvende tutar."}],"ans":"Evet, hücrenin bilgileri (DNA) çekirdeğin içinde saklanır."},{"q":"Çekirdeğin etrafında bir kabuk gibi yapı var mıdır?","steps":[{"t":"Çekirdeği koruyan yapı","a":"İnce bir örtü","d":"Çekirdeğin etrafında onu çevreleyen ince bir örtü bulunur. Bu örtü çekirdeği korur. Bir yumurta kabuğuna benzetilebilir."},{"t":"Bu yapı nedir?","a":"Çekirdek zarı","d":"Çekirdeği çevreleyen örtüye çekirdek zarı denir. Bu zar çekirdeği dış kısımdan ayırır. Üzerinde küçük delikler vardır."}],"ans":"Evet, çekirdeğin etrafında onu çevreleyen çekirdek zarı bulunur."},{"q":"Bir hücrede genellikle kaç tane çekirdek bulunur?","steps":[{"t":"Çekirdek sayısı","a":"Genelde bir tane","d":"Çoğu hücrede bir tane çekirdek bulunur. Bu tek çekirdek hücreyi yönetmeye yeter. Hücrenin ortasında ya da yakınında durur."},{"t":"Sonuç","a":"Bir çekirdek","d":"Genellikle her hücrede bir çekirdek vardır. Bu çekirdek hücrenin tüm işlerini düzenler. Yani çoğunlukla tek çekirdek görürüz."}],"ans":"Bir hücrede genellikle bir tane çekirdek bulunur."},{"q":"Çekirdek olmadan hücre kendini yönetebilir mi?","steps":[{"t":"Çekirdeğin görevi","a":"Yönetmek","d":"Çekirdek hücrenin yöneticisidir. Hücreye ne yapacağını söyler. Onsuz hücre yönsüz kalır."},{"t":"Çekirdek olmazsa","a":"Yönetemez","d":"Çekirdek olmazsa hücre kendini düzgün yönetemez. Çünkü gerekli bilgiler ve komutlar çekirdektedir. Bu yüzden çekirdek hücre için çok önemlidir."}],"ans":"Hayır, çekirdek olmadan hücre kendini düzgün yönetemez."}],"zor":[{"q":"Çekirdek zarının üzerindeki delikler ne işe yarar?","steps":[{"t":"Çekirdek zarı","a":"Çekirdeği çevreler","d":"Çekirdek zarı çekirdeğin etrafını saran ince bir örtüdür. Çekirdeği dışarıdan ayırır. Üzerinde küçük delikler bulunur."},{"t":"Deliklerin görevi","a":"Madde geçişi","d":"Bu küçük deliklerden bazı maddeler içeri ve dışarı geçebilir. Yani delikler bir kapı gibi çalışır. Böylece çekirdek ile hücrenin diğer bölümleri haberleşir."}],"ans":"Çekirdek zarındaki delikler, madde geçişini sağlayarak çekirdek ile hücrenin diğer kısımlarının haberleşmesine yarar."},{"q":"DNA çekirdeğin içinde nasıl bulunur?","steps":[{"t":"DNA nedir?","a":"Bilgi maddesi","d":"DNA hücrenin tüm bilgilerini taşıyan maddedir. Hücrenin nasıl çalışacağını belirler. Çok önemli bir kalıtım maddesidir."},{"t":"Nasıl durur?","a":"İplikler hâlinde","d":"DNA çekirdeğin içinde ince iplikler hâlinde bulunur. Bu ipliklere kromatin denir. İplikler çekirdeğin içine dağılmış durumdadır."}],"ans":"DNA, çekirdeğin içinde kromatin adı verilen ince iplikler hâlinde bulunur."},{"q":"Çekirdekçik (nukleolus) çekirdeğin neresinde bulunur ve ne işe yarar?","steps":[{"t":"Çekirdekçik nerede?","a":"Çekirdeğin içinde","d":"Çekirdekçik çekirdeğin içinde bulunan küçük, koyu renkli bir bölümdür. Çekirdeğin ortasına yakın durur. Çekirdeğin içindeki özel bir yapıdır."},{"t":"Görevi nedir?","a":"Ribozom üretir","d":"Çekirdekçik ribozom adı verilen yapıların üretilmesine yardım eder. Ribozomlar hücrede protein yapımında görev alır. Yani çekirdekçik bu üretimin başladığı yerdir."}],"ans":"Çekirdekçik, çekirdeğin içinde bulunur ve ribozomların üretimine yardım eder."},{"q":"Bir hücreden çekirdek alınırsa ne olur?","steps":[{"t":"Çekirdeğin önemi","a":"Yönetici","d":"Çekirdek hücreyi yöneten ve bilgileri saklayan merkezdir. Hücrenin tüm işlerini düzenler. Hücrenin yaşaması için gereklidir."},{"t":"Çekirdek alınırsa","a":"Hücre yaşayamaz","d":"Çekirdek alınırsa hücre yöneticisini kaybeder. Bilgi ve komutlar olmadan işlevlerini sürdüremez. Bir süre sonra hücre yaşamını yitirir."}],"ans":"Bir hücreden çekirdek alınırsa hücre yönetimini kaybeder ve bir süre sonra yaşamını sürdüremez."},{"q":"Çekirdek ve çekirdekçik arasındaki ilişki nedir?","steps":[{"t":"Çekirdek","a":"Büyük yapı","d":"Çekirdek hücrenin yönetim merkezidir ve DNA'yı korur. İçinde başka yapılar da bulunur. Hücrenin en önemli bölümlerindendir."},{"t":"Çekirdekçik","a":"İçindeki küçük yapı","d":"Çekirdekçik, çekirdeğin içinde yer alan daha küçük bir yapıdır. Ribozom üretimine yardım eder. Çekirdeğin bir parçası gibidir."},{"t":"İlişki","a":"İç içe yapılar","d":"Çekirdekçik çekirdeğin içinde bulunur, yani çekirdek dıştadır, çekirdekçik içtedir. İkisi birlikte çalışır. Çekirdek koruma, çekirdekçik üretim işine yardımcı olur."}],"ans":"Çekirdekçik, çekirdeğin içinde yer alan küçük bir yapıdır; çekirdek dışta yönetimi sağlar, çekirdekçik ise içte ribozom üretimine yardım eder."}]},"ortaokul":{"kolay":[{"q":"Çekirdek zarının seçici geçirgen olması ne anlama gelir?","steps":[{"t":"Çekirdek zarı","a":"Sınır oluşturur","d":"Çekirdek zarı çekirdeği sitoplazmadan ayıran çift katlı bir zardır. Çekirdeğin içini dışından korur. Üzerinde porlar bulunur."},{"t":"Seçici geçirgenlik","a":"Bazı maddeleri geçirir","d":"Seçici geçirgen olmak, zarın her maddeyi değil yalnızca bazılarını geçirmesi demektir. Porlar hangi maddenin geçeceğine yardımcı olur. Böylece çekirdeğin iç ortamı denetlenir."}],"ans":"Çekirdek zarının seçici geçirgen olması, yalnızca belirli maddelerin porlardan geçişine izin vermesi anlamına gelir."},{"q":"Çekirdekçiğin temel görevi nedir?","steps":[{"t":"Çekirdekçik nedir?","a":"Çekirdek içi yapı","d":"Çekirdekçik, çekirdeğin içinde zarsız ve yoğun görünen bir bölümdür. Çekirdeğin önemli bir parçasıdır. Burada özel bir üretim gerçekleşir."},{"t":"Görevi","a":"Ribozom üretimi","d":"Çekirdekçik ribozomların yapımında görev alır. Ribozomlar daha sonra sitoplazmaya geçerek protein üretir. Yani çekirdekçik protein üretiminin başlangıcına katkı sağlar."}],"ans":"Çekirdekçiğin temel görevi ribozomların üretilmesini sağlamaktır."},{"q":"Kromatin nedir?","steps":[{"t":"Çekirdek içinde DNA","a":"İplik hâlinde","d":"Hücre bölünmediği zaman DNA çekirdek içinde dağınık iplikler hâlinde bulunur. Bu iplikler proteinlerle birlikte durur. Çekirdeğin içine yayılmıştır."},{"t":"Adı nedir?","a":"Kromatin","d":"DNA ve proteinlerin oluşturduğu bu iplik yapıya kromatin denir. Hücre bölüneceği zaman kromatin kısalıp kalınlaşarak kromozomları oluşturur. Yani kromatin DNA'nın bölünme dışındaki hâlidir."}],"ans":"Kromatin, çekirdek içinde DNA ile proteinlerin oluşturduğu iplik biçimindeki yapıdır."},{"q":"Neden çekirdek hücrenin yönetim merkezi olarak adlandırılır?","steps":[{"t":"Çekirdekte ne var?","a":"DNA bulunur","d":"Çekirdeğin içinde hücrenin tüm bilgilerini taşıyan DNA bulunur. Bu bilgiler hücrenin işlevlerini belirler. Hücre bu bilgilere göre çalışır."},{"t":"Yönetim nasıl olur?","a":"DNA komut verir","d":"DNA, hücrenin hangi proteini üreteceğini ve nasıl davranacağını belirler. Yani çekirdek komutların kaynağıdır. Bu nedenle hücreyi yönetir."},{"t":"Sonuç","a":"Yönetim merkezi","d":"DNA'yı barındıran ve komutları yöneten çekirdeğe yönetim merkezi denir. Hücrenin tüm işleri çekirdekten yönlendirilir. Bu yüzden bu ad verilmiştir."}],"ans":"Çekirdek, hücrenin işlevlerini belirleyen DNA'yı barındırıp komutları yönettiği için yönetim merkezi olarak adlandırılır."},{"q":"Çekirdek zarı kaç katlıdır?","steps":[{"t":"Çekirdek zarının yapısı","a":"İki katlı","d":"Çekirdek zarı tek katlı değil, iki katlı bir yapıdadır. Yani bir iç ve bir dış zar bulunur. Bu çift katlı yapı çekirdeği daha iyi korur."},{"t":"Sonuç","a":"Çift zar","d":"Çekirdek zarı çift katlıdır ve üzerinde porlar bulunur. İki kat arasında küçük bir boşluk vardır. Porlar bu iki katı bağlayarak madde geçişini sağlar."}],"ans":"Çekirdek zarı çift (iki) katlıdır ve üzerinde porlar bulunur."}],"zor":[{"q":"Çekirdekçikte üretilen ribozomlar nasıl bir yolculuk izleyerek görev yapar?","steps":[{"t":"Üretim yeri","a":"Çekirdekçik","d":"Ribozomların yapımı çekirdek içindeki çekirdekçikte başlar. Burada ribozomun parçaları hazırlanır. Çekirdekçik bu üretimin merkezidir."},{"t":"Çekirdekten çıkış","a":"Porlardan geçer","d":"Hazırlanan ribozom parçaları çekirdek zarındaki porlardan sitoplazmaya geçer. Porlar bu geçişe izin verir. Böylece ribozomlar çekirdeği terk eder."},{"t":"Görev yeri","a":"Sitoplazmada protein üretimi","d":"Sitoplazmaya ulaşan ribozomlar protein üretmeye başlar. Bazıları serbest, bazıları endoplazmik retikuluma bağlı çalışır. Böylece çekirdekçikte başlayan yolculuk sitoplazmada görevle tamamlanır."}],"ans":"Ribozomlar çekirdekçikte üretilir, çekirdek zarının porlarından sitoplazmaya geçer ve orada protein üretiminde görev yapar."},{"q":"Hücre bölüneceği zaman kromatin neden kromozom hâline gelir?","steps":[{"t":"Kromatinin hâli","a":"Dağınık iplik","d":"Hücre bölünmediği zaman DNA, dağınık ve uzun kromatin iplikleri hâlindedir. Bu hâl gen okumaya uygundur. Ancak taşınmaya pek elverişli değildir."},{"t":"Bölünme ihtiyacı","a":"Düzgün paylaşım","d":"Hücre bölüneceği zaman DNA'nın iki yeni hücreye eşit ve hatasız paylaşılması gerekir. Dağınık iplikler bu paylaşımda karışabilir. Bu yüzden daha düzenli bir biçim gerekir."},{"t":"Kromozom oluşumu","a":"Kısalıp kalınlaşır","d":"Kromatin kısalıp kalınlaşarak yoğun kromozomlar oluşturur. Kromozomlar taşınması kolay paketlerdir. Böylece DNA güvenli biçimde paylaştırılabilir."}],"ans":"DNA'nın yeni hücrelere düzgün ve hatasız paylaştırılabilmesi için, dağınık kromatin kısalıp kalınlaşarak kromozom hâline gelir."},{"q":"Çekirdek zarındaki porlar olmasaydı hücrede hangi sorun yaşanırdı?","steps":[{"t":"Porların görevi","a":"Madde geçişi","d":"Çekirdek zarındaki porlar, çekirdek ile sitoplazma arasında madde geçişini sağlar. RNA ve ribozom parçaları bu porlardan geçer. Böylece çekirdek dışıyla bağlantı kurar."},{"t":"Por olmasaydı","a":"Geçiş engellenir","d":"Porlar olmasaydı çekirdek içinde üretilen maddeler dışarı çıkamazdı. Sitoplazmadan gerekli maddeler de içeri giremezdi. Çekirdek tamamen yalıtılmış olurdu."},{"t":"Sonuç","a":"Protein üretimi durur","d":"RNA sitoplazmaya çıkamayınca protein üretimi gerçekleşemezdi. Hücre yaşamsal işlevlerini sürdüremezdi. Bu da hücrenin ölümüne yol açardı."}],"ans":"Porlar olmasaydı RNA ve ribozomlar çekirdekten çıkamaz, protein üretimi duracağı için hücre yaşamsal işlevlerini sürdüremezdi."},{"q":"İçinde çekirdekçik belirgin görünen bir hücre hakkında ne söylenebilir?","steps":[{"t":"Çekirdekçiğin görevi","a":"Ribozom üretimi","d":"Çekirdekçik ribozomların üretildiği yerdir. Ribozomlar ise protein sentezinde görev alır. Yani çekirdekçik protein üretimiyle ilişkilidir."},{"t":"Belirgin çekirdekçik","a":"Yoğun üretim","d":"Çekirdekçiğin büyük ve belirgin olması, o hücrenin çok ribozom ürettiğini gösterir. Çok ribozom çok protein demektir. Demek ki hücre yoğun protein sentezi yapmaktadır."},{"t":"Sonuç","a":"Aktif hücre","d":"Belirgin çekirdekçik, hücrenin protein üretiminde çok etkin olduğunu işaret eder. Örneğin salgı yapan hücrelerde çekirdekçik belirgindir. Yani bu hücre aktif bir protein üreticisidir."}],"ans":"Belirgin bir çekirdekçik, o hücrenin çok ribozom üretip yoğun protein sentezi yapan aktif bir hücre olduğunu gösterir."},{"q":"Olgun alyuvarlarda çekirdek bulunmaması neyi sağlar?","steps":[{"t":"Alyuvarın görevi","a":"Oksijen taşımak","d":"Alyuvarlar kanda oksijen taşıyan hücrelerdir. Görevlerini iyi yapmak için bol oksijen bağlamaları gerekir. İçlerinde mümkün olduğunca çok yer oksijen taşıyıcı maddeye ayrılmalıdır."},{"t":"Çekirdeğin atılması","a":"Yer açılır","d":"Olgun insan alyuvarları çekirdeklerini kaybeder. Böylece çekirdeğin kapladığı yer boşalır. Bu boş yer oksijen taşıyan maddeyle dolar."},{"t":"Sonuç","a":"Daha çok oksijen","d":"Çekirdek olmadığı için alyuvar daha çok oksijen taşıyıcı madde barındırır. Ayrıca esnek yapısı dar damarlardan geçmeyi kolaylaştırır. Yani çekirdeksizlik alyuvarın görevini kolaylaştırır."}],"ans":"Çekirdeğin atılması alyuvarda yer açar; bu sayede hücre daha çok oksijen taşıyıcı madde barındırır ve esnek yapısıyla dar damarlardan kolayca geçer."}]},"lise":{"kolay":[{"q":"Çekirdek zarının çift katlı yapısı endoplazmik retikulumla nasıl bir ilişki içindedir?","steps":[{"t":"Çift zarın yapısı","a":"İç ve dış zar","d":"Çekirdek zarı iç ve dış olmak üzere iki katmandan oluşur. İki kat arasında küçük bir boşluk bulunur. Bu yapı çekirdeği güvenle kuşatır."},{"t":"Dış zarın devamı","a":"ER ile süreklilik","d":"Çekirdek zarının dış katmanı endoplazmik retikulum zarıyla devam eder. Yani ikisi birbirine bağlıdır. Bu süreklilik madde taşınmasını kolaylaştırır."},{"t":"Sonuç","a":"Bağlantılı sistem","d":"Çekirdek zarı ile endoplazmik retikulum bağlantılı bir zar sistemi oluşturur. Bu sayede çekirdek ve sitoplazma arasındaki madde akışı düzenli yürür. İki yapı uyum içinde çalışır."}],"ans":"Çekirdek zarının dış katmanı endoplazmik retikulum zarıyla süreklilik gösterir; böylece ikisi bağlantılı bir zar sistemi oluşturur."},{"q":"Çekirdek porları madde geçişini nasıl denetler?","steps":[{"t":"Por yapısı","a":"Protein kompleksi","d":"Çekirdek porları, zarda yer alan özel protein gruplarından oluşur. Bu yapılar bir kapı gibi davranır. Her maddenin geçişine izin vermezler."},{"t":"Denetim mekanizması","a":"Seçici geçiş","d":"Porlar küçük molekülleri kolayca geçirirken büyük molekülleri denetimle geçirir. RNA ve proteinler tanınarak içeri ya da dışarı alınır. Böylece geçiş düzenli olur."},{"t":"Sonuç","a":"Kontrollü alışveriş","d":"Porlar sayesinde çekirdek ile sitoplazma arasındaki madde alışverişi denetlenir. Gerekli maddeler geçerken gereksizler engellenir. Bu denetim çekirdeğin iç ortamını korur."}],"ans":"Çekirdek porları, protein kompleksleriyle hangi molekülün geçeceğini seçerek çekirdek ile sitoplazma arasındaki madde alışverişini kontrollü biçimde yürütür."},{"q":"Çekirdekçik neden hücre bölünmesi sırasında kaybolup yeniden oluşur?","steps":[{"t":"Çekirdekçiğin yapısı","a":"Zarsız yoğunlaşma","d":"Çekirdekçik zarla çevrili değildir; ribozom üretiminin yoğunlaştığı bir bölgedir. Belirli kromozom bölgelerinin etrafında oluşur. Yani sabit zarlı bir organel değildir."},{"t":"Bölünmede ne olur?","a":"Kromozomlar yoğunlaşır","d":"Hücre bölünürken kromatin kromozomlara yoğunlaşır ve çekirdekçik dağılır. Ribozom üretimi durduğu için çekirdekçik görünmez olur. Bu nedenle bölünme sırasında kaybolur."},{"t":"Yeniden oluşum","a":"Bölünme sonrası","d":"Bölünme bittiğinde kromozomlar tekrar kromatine açılır ve çekirdekçik yeniden belirir. İlgili kromozom bölgeleri tekrar bir araya gelir. Böylece ribozom üretimi yeniden başlar."}],"ans":"Çekirdekçik zarsız bir yoğunlaşma olduğundan, bölünmede kromozomlar yoğunlaşınca dağılır ve bölünme bitince ilgili bölgeler yeniden toplanarak yeniden oluşur."},{"q":"Çekirdek içindeki DNA neden proteinlerle birlikte paketlenir?","steps":[{"t":"DNA'nın uzunluğu","a":"Çok uzun","d":"Bir hücredeki DNA açıldığında çok uzun bir iplik oluşturur. Bu uzunluk küçük çekirdeğe sığmaz görünür. Bu yüzden düzenli paketlenmesi gerekir."},{"t":"Proteinlerin rolü","a":"Sarma görevi","d":"DNA, histon adı verilen proteinlerin etrafına sarılır. Bu sarma DNA'yı düzenli ve sıkı paketler. Böylece uzun iplik küçük bir alana sığar."},{"t":"Sonuç","a":"Düzenli paketleme","d":"Proteinlerle paketlenen DNA, çekirdeğe sığacak biçimde düzenlenir. Bu paket kromatini oluşturur. Düzenli paketleme aynı zamanda gen okumayı da kolaylaştırır."}],"ans":"Çok uzun olan DNA, histon proteinlerine sarılarak küçük çekirdeğe sığacak biçimde düzenli paketlenir."},{"q":"Bir hücrede birden fazla çekirdek görülmesi mümkün müdür?","steps":[{"t":"Tipik durum","a":"Tek çekirdek","d":"Çoğu hücrede yalnızca bir çekirdek bulunur. Bu çekirdek hücrenin yönetimini tek başına yürütür. Genel kural budur."},{"t":"İstisna","a":"Bazı hücreler çok çekirdekli","d":"Bazı özel hücreler birden fazla çekirdek taşıyabilir. Örneğin çizgili kas hücreleri çok çekirdeklidir. Bu hücreler birden çok çekirdeğe ihtiyaç duyar."},{"t":"Sonuç","a":"Mümkündür","d":"Yani bir hücrede birden fazla çekirdek görülmesi mümkündür. Bu durum hücrenin büyüklüğü ve görevine bağlıdır. Çok görevli büyük hücreler birden çok çekirdek bulundurabilir."}],"ans":"Evet; çoğu hücrede tek çekirdek olsa da çizgili kas gibi bazı hücreler birden fazla çekirdek taşıyabilir."},{"q":"Çekirdek zarı hücre bölünmesi sırasında ne olur?","steps":[{"t":"Bölünme öncesi","a":"Zar bütündür","d":"Bölünme başlamadan önce çekirdek zarı çekirdeği bütünüyle çevreler. DNA bu zarın içinde korunur. Yapı düzenli ve kapalıdır."},{"t":"Bölünme sırasında","a":"Zar parçalanır","d":"Hücre bölünürken çekirdek zarı parçalanıp dağılır. Böylece kromozomlar serbest kalır ve hücrenin iki kutbuna çekilebilir. Bu, DNA'nın paylaşılması için gereklidir."},{"t":"Bölünme sonrası","a":"Zar yeniden oluşur","d":"Bölünme tamamlandığında yeni hücrelerin her birinde çekirdek zarı yeniden oluşur. Kromozomların etrafı tekrar sarılır. Böylece iki yeni çekirdek meydana gelir."}],"ans":"Çekirdek zarı bölünme sırasında parçalanır, kromozomların paylaşımı tamamlanınca yeni hücrelerin her birinde yeniden oluşur."},{"q":"Çekirdekteki DNA hangi süreçle RNA'ya kopyalanır?","steps":[{"t":"DNA'nın yeri","a":"Çekirdekte","d":"DNA çekirdek içinde korunan kalıtım maddesidir. Bilgilerin kullanılması için önce bir kopya oluşturulması gerekir. Bu işlem çekirdekte başlar."},{"t":"Kopyalama süreci","a":"Transkripsiyon","d":"DNA'daki bilginin RNA'ya yazılmasına transkripsiyon denir. Bu süreç çekirdek içinde gerçekleşir. Üretilen RNA daha sonra sitoplazmaya geçer."}],"ans":"Çekirdekteki DNA, transkripsiyon süreciyle RNA'ya kopyalanır."},{"q":"Çekirdek sıvısına (nükleoplazma) ne ad verilir ve görevi nedir?","steps":[{"t":"Nükleoplazma nedir?","a":"Çekirdek içi sıvı","d":"Çekirdeğin içini dolduran sıvıya nükleoplazma denir. Bu sıvı çekirdek zarının içinde bulunur. İçinde DNA ve çekirdekçik yüzer."},{"t":"Görevi","a":"Ortam sağlamak","d":"Nükleoplazma, çekirdek içi tepkimelerin gerçekleştiği ortamı sağlar. DNA'nın kopyalanması gibi işlemler bu sıvıda yürür. Ayrıca gerekli maddeleri çekirdek içinde taşır."}],"ans":"Çekirdek içini dolduran sıvıya nükleoplazma denir; çekirdek içi tepkimelerin gerçekleştiği ortamı ve madde taşınmasını sağlar."},{"q":"Çekirdek ile ribozom arasında nasıl bir görev ilişkisi vardır?","steps":[{"t":"Çekirdeğin rolü","a":"Bilgi ve yapı sağlar","d":"Çekirdek, üretilecek proteinin bilgisini DNA'da taşır. Ayrıca çekirdekçiğinde ribozomun yapı taşları üretilir. Yani üretimin planı ve aracı çekirdekten gelir."},{"t":"Ribozomun rolü","a":"Proteini üretir","d":"Ribozom, çekirdekten gelen bilgiye göre protein üretir. Sitoplazmada görev yapar. Çekirdekten gelen RNA'yı okuyarak proteini birleştirir."},{"t":"İlişki","a":"Plan ve uygulama","d":"Çekirdek planı ve ribozomun yapısını sağlarken, ribozom bu planı uygulayarak proteini üretir. İki yapı uyumla çalışır. Biri yönetir, diğeri üretir."}],"ans":"Çekirdek protein bilgisini (DNA/RNA) ve ribozomun yapı taşlarını sağlar; ribozom ise bu bilgiye göre sitoplazmada proteini üretir."},{"q":"Sinir hücreleri gibi bazı hücrelerde çekirdek büyük olabilir; bu neyi gösterir?","steps":[{"t":"Büyük çekirdek","a":"Çok DNA etkinliği","d":"Çekirdeğin büyük olması, içinde DNA ile ilgili işlerin yoğun yapıldığını düşündürür. Çok sayıda gen etkin olabilir. Bu durum hücrenin etkin olduğunu gösterir."},{"t":"Hücrenin ihtiyacı","a":"Çok protein gerektirir","d":"Sinir hücreleri sürekli iletim yapar ve birçok protein üretmek zorundadır. Bu yüksek üretim için çekirdek yoğun çalışır. Bu nedenle çekirdek büyük görünebilir."},{"t":"Sonuç","a":"Aktif yönetim","d":"Büyük çekirdek, hücrenin yoğun gen etkinliği ve protein üretimi yaptığını gösterir. Yani hücre metabolik olarak çok etkindir. Çekirdek bu etkinliği yönetir."}],"ans":"Büyük çekirdek, hücrenin yoğun gen etkinliği ve protein üretimi yaptığı, metabolik olarak çok aktif olduğu anlamına gelir."},{"q":"Çekirdek zarının dış yüzeyinde ribozomlar görülebilir mi?","steps":[{"t":"Dış zar ve ER","a":"Süreklilik var","d":"Çekirdek zarının dış katmanı endoplazmik retikulumla devam eder. Endoplazmik retikulumun bazı bölümlerinde ribozomlar bulunur. Bu süreklilik dış zarı da etkiler."},{"t":"Ribozomların yeri","a":"Dış zara bağlı","d":"Bu nedenle çekirdek zarının dış yüzeyinde de ribozomlar yer alabilir. Bu ribozomlar protein üretir. Dış zar adeta endoplazmik retikulumun bir parçası gibidir."}],"ans":"Evet; çekirdek zarının dış katmanı endoplazmik retikulumla sürekli olduğundan dış yüzeyinde ribozomlar görülebilir."},{"q":"Çekirdekteki kromatin ne kadar gevşek ya da sıkı olursa gen okuması nasıl etkilenir?","steps":[{"t":"Gevşek kromatin","a":"Okumaya açık","d":"Kromatin gevşek olduğunda DNA daha erişilebilir hâldedir. Gen okuma araçları DNA'ya kolayca ulaşır. Bu durumda ilgili genler etkin biçimde okunabilir."},{"t":"Sıkı kromatin","a":"Okumaya kapalı","d":"Kromatin sıkı paketlendiğinde DNA erişilmesi zor hâle gelir. Gen okuma araçları bu bölgeye ulaşamaz. Bu durumda ilgili genler okunamaz."},{"t":"Sonuç","a":"Paketlenme düzenler","d":"Kromatinin gevşekliği ya da sıkılığı, hangi genlerin okunacağını belirler. Gevşek bölgeler etkin, sıkı bölgeler etkisizdir. Böylece hücre gen etkinliğini düzenler."}],"ans":"Gevşek kromatin DNA'yı erişilebilir kılıp gen okumasını kolaylaştırır; sıkı kromatin ise erişimi engelleyerek gen okumasını durdurur."},{"q":"Çekirdek, ökaryot hücreyi prokaryottan ayıran en belirgin yapı olarak neden gösterilir?","steps":[{"t":"Prokaryotta durum","a":"Çekirdek yok","d":"Prokaryot hücrelerde zarla çevrili gerçek bir çekirdek bulunmaz. DNA sitoplazmada serbest durur. Bu, prokaryotun temel özelliğidir."},{"t":"Ökaryotta durum","a":"Çekirdek var","d":"Ökaryot hücrelerde zarla çevrili gerçek bir çekirdek bulunur. DNA bu çekirdek içinde korunur. Bu özellik ökaryotu tanımlar."},{"t":"Sonuç","a":"Ayırt edici yapı","d":"Çekirdeğin varlığı doğrudan ökaryotu, yokluğu prokaryotu işaret eder. Bu yüzden çekirdek en belirgin ayırt edici yapıdır. İki hücre tipini ilk bakışta bu özellik ayırır."}],"ans":"Çekirdek prokaryotta bulunmayıp ökaryotta bulunduğundan, iki hücre tipini ayıran en belirgin yapıdır."},{"q":"Çekirdekçik sayısı bir hücrede neye göre değişebilir?","steps":[{"t":"Çekirdekçiğin görevi","a":"Ribozom üretimi","d":"Çekirdekçik ribozom üretiminin yoğunlaştığı bölgedir. Hücrenin protein üretim ihtiyacıyla doğrudan ilgilidir. Çok protein gereken hücre çok ribozom üretir."},{"t":"Sayının değişimi","a":"İhtiyaca bağlı","d":"Protein üretimi çok olan hücrelerde çekirdekçik sayısı ya da büyüklüğü artabilir. Az protein üreten hücrelerde ise küçük ya da az olabilir. Yani sayı ihtiyaca göre değişir."}],"ans":"Çekirdekçik sayısı, hücrenin protein (ribozom) üretim ihtiyacına göre değişebilir; çok üreten hücrelerde artar."},{"q":"Çekirdek zarının iç ve dış katmanları arasındaki boşluğun adı ve önemi nedir?","steps":[{"t":"İki katman arası","a":"Perinükleer boşluk","d":"Çekirdek zarının iç ve dış katmanı arasında ince bir boşluk bulunur. Bu boşluğa perinükleer boşluk denir. İki zarı birbirinden ayrı tutar."},{"t":"Önemi","a":"ER ile bağlantı","d":"Bu boşluk endoplazmik retikulumun iç boşluğuyla bağlantılıdır. Böylece çekirdek zarı ve endoplazmik retikulum tek bir sistem gibi davranır. Bu bağlantı madde taşınmasını kolaylaştırır."}],"ans":"Çekirdek zarının iki katmanı arasındaki boşluğa perinükleer boşluk denir; endoplazmik retikulumla bağlantılı olduğundan madde taşınmasında rol oynar."}],"zor":[{"q":"Bir bilim insanı çekirdeği alınmış bir amip hücresine başka bir hücreden çekirdek naklediyor; hücrenin hayatta kalması neyi kanıtlar?","steps":[{"t":"Çekirdeksiz hücre","a":"Yönetimsiz kalır","d":"Çekirdeği alınan hücre yönetim merkezini kaybeder. DNA olmadan gerekli proteinler üretilemez. Bu durumda hücre bir süre sonra ölür."},{"t":"Çekirdek nakli","a":"Yönetim geri gelir","d":"Başka bir hücreden çekirdek nakledildiğinde hücre yeni bir DNA kaynağı kazanır. Bu DNA komutları yeniden üretir. Böylece hücrenin işlevleri tekrar başlar."},{"t":"Hücre yaşarsa","a":"Çekirdek hayati","d":"Nakil sonrası hücrenin yaşaması, çekirdeğin yaşam için zorunlu olduğunu gösterir. Çekirdek olmadan hücre sürdürülemez, çekirdekle yeniden canlanır. Bu deney çekirdeğin yönetim merkezi olduğunu kanıtlar."},{"t":"Sonuç","a":"Yönetim merkezi","d":"Deney, hücrenin yaşamsal işlevlerinin çekirdek tarafından yönetildiğini ortaya koyar. Çekirdek alınınca durur, eklenince devam eder. Bu da çekirdeğin yönetim merkezi olduğunu deneysel olarak kanıtlar."}],"ans":"Çekirdeksiz hücrenin ölmesi, çekirdek nakliyle yeniden yaşaması; çekirdeğin hücrenin yaşamsal işlevlerini yöneten merkez olduğunu deneysel olarak kanıtlar."},{"q":"Histon proteinlerinin kimyasal değişimi gen etkinliğini nasıl düzenler?","steps":[{"t":"Histonların rolü","a":"DNA'yı sarar","d":"Histonlar, DNA'nın etrafına sarıldığı proteinlerdir. DNA bu proteinlere sarılarak paketlenir. Sarılma sıkılığı genlere erişimi belirler."},{"t":"Kimyasal değişim","a":"Paketi gevşetir/sıkar","d":"Histonlara eklenen bazı kimyasal gruplar DNA'nın sarılmasını gevşetebilir ya da sıkılaştırabilir. Gevşeyen bölgelerde DNA erişilebilir olur. Sıkılaşan bölgelerde ise erişim engellenir."},{"t":"Etkisi","a":"Geni açar/kapatır","d":"Gevşeyen bölgelerdeki genler okunabilir, yani etkinleşir. Sıkılaşan bölgelerdeki genler okunamaz, yani etkisizleşir. Böylece histon değişimi gen açıp kapamasını sağlar."},{"t":"Sonuç","a":"İnce gen denetimi","d":"Histonların kimyasal değişimi, hücrenin hangi genleri kullanacağını ince ayarla belirler. Bu, DNA dizilimini değiştirmeden gen etkinliğini düzenler. Böylece aynı DNA'ya sahip hücreler farklı işler yapabilir."}],"ans":"Histonlardaki kimyasal değişimler DNA paketini gevşetip sıkarak ilgili genleri erişilebilir ya da erişilemez kılar; böylece DNA dizisi değişmeden gen etkinliği düzenlenir."},{"q":"mRNA'nın çekirdekte işlenip olgunlaşması protein üretiminin doğruluğunu nasıl güvence altına alır?","steps":[{"t":"İlk mRNA","a":"Ham hâl","d":"Çekirdekte DNA'dan kopyalanan ilk RNA ham, yani işlenmemiş hâldedir. İçinde proteine çevrilmeyecek gereksiz bölümler bulunur. Bu hâliyle doğrudan kullanılamaz."},{"t":"İşlenme","a":"Gereksizler çıkarılır","d":"Çekirdekte ham RNA işlenir; gereksiz bölümler çıkarılır ve uçları korunaklı hâle getirilir. Böylece anlamlı bölümler bir araya gelir. Bu işleme RNA olgunlaşması denir."},{"t":"Sitoplazmaya geçiş","a":"Olgun mRNA çıkar","d":"Yalnızca olgunlaşmış, doğru mRNA çekirdek porlarından sitoplazmaya geçer. Hatalı ya da yarım RNA genelde geçemez. Böylece bir denetim noktası oluşur."},{"t":"Sonuç","a":"Doğru protein","d":"Sitoplazmaya yalnızca doğru mRNA ulaştığından ribozom doğru proteini üretir. Çekirdekteki işlenme bir kalite kontrolü sağlar. Böylece protein üretiminin doğruluğu güvence altına alınır."}],"ans":"Çekirdekte ham RNA'nın gereksiz bölümleri çıkarılıp olgunlaştırılır ve yalnızca doğru mRNA sitoplazmaya geçer; bu kalite kontrolü doğru protein üretimini güvence altına alır."},{"q":"Çekirdek zarının bölünme sırasında parçalanıp yeniden oluşması, bu zarın yapısı hakkında ne söyler?","steps":[{"t":"Parçalanma","a":"Zar dağılabiliyor","d":"Çekirdek zarı bölünme sırasında küçük parçalara, yani zar keseciklerine ayrılabilir. Bu, zarın katı ve sabit olmadığını gösterir. Aksine esnek ve dinamik bir yapıdadır."},{"t":"Yeniden oluşum","a":"Zar birleşebiliyor","d":"Bölünme bittiğinde dağılan zar parçaları yeniden birleşerek çekirdek zarını oluşturur. Bu birleşme, zarın akışkan yapı taşlarından oluştuğunu gösterir. Zar adeta yeniden kurulabilir."},{"t":"Yapısal sonuç","a":"Akışkan zar","d":"Parçalanıp yeniden oluşabilmesi, çekirdek zarının akışkan bir yapıya sahip olduğunu kanıtlar. Zar, hareketli yapı taşlarından oluşur. Bu akışkanlık zarın esnekliğini sağlar."},{"t":"Sonuç","a":"Dinamik yapı","d":"Çekirdek zarı sabit bir duvar değil, dinamik ve akışkan bir yapıdır. Bu özellik ona parçalanıp yeniden kurulma yeteneği kazandırır. Böylece bölünme süreci sorunsuz yürütülür."}],"ans":"Bölünmede parçalanıp yeniden oluşabilmesi, çekirdek zarının katı bir duvar değil, akışkan ve dinamik yapı taşlarından oluştuğunu gösterir."},{"q":"Aynı DNA'ya sahip kas ve sinir hücreleri neden farklı proteinler üretir; bu durumu çekirdek üzerinden açıklayınız.","steps":[{"t":"Ortak DNA","a":"Aynı bilgi","d":"Bir bireyin tüm hücreleri aynı DNA'yı taşır. Yani kas ve sinir hücresi aynı genetik bilgiye sahiptir. Buna rağmen farklı proteinler üretirler."},{"t":"Seçici gen okuma","a":"Bazı genler etkin","d":"Her hücrede DNA'nın yalnızca bir kısmı okunur. Kas hücresinde kasla ilgili genler etkinken sinir hücresinde sinirle ilgili genler etkindir. Yani çekirdekte farklı genler açılır."},{"t":"Kromatin düzenlenmesi","a":"Açık/kapalı bölgeler","d":"Çekirdekte kromatinin gevşek ve sıkı bölgeleri her hücre tipinde farklıdır. Açık bölgelerdeki genler okunur, kapalı bölgelerdekiler okunmaz. Bu düzenleme hücre tipine göre değişir."},{"t":"Sonuç","a":"Farklı protein","d":"Aynı DNA olsa da farklı genlerin okunması farklı proteinlerin üretilmesini sağlar. Bu seçici okuma çekirdekte yönetilir. Böylece tek bir DNA'dan farklı hücre tipleri oluşur."}],"ans":"Tüm hücreler aynı DNA'yı taşısa da çekirdekte farklı genler seçici biçimde okunduğundan, kas ve sinir hücreleri kendilerine özgü farklı proteinleri üretir."},{"q":"Çekirdekçik bozulan bir hücrede zamanla hangi yaşamsal sorunlar zinciri ortaya çıkar?","steps":[{"t":"Çekirdekçik bozulması","a":"Ribozom üretimi düşer","d":"Çekirdekçik ribozom üretiminden sorumludur. Bozulduğunda yeni ribozom üretimi azalır. Hücredeki ribozom sayısı zamanla düşer."},{"t":"Protein sentezi","a":"Azalır","d":"Ribozom azalınca protein üretimi de düşer. Hücre, ihtiyaç duyduğu enzimleri ve yapı proteinlerini yeterince üretemez. Birçok işlev aksamaya başlar."},{"t":"İşlevsel bozulma","a":"Tepkimeler durur","d":"Enzim eksikliği nedeniyle hücre içi tepkimeler yavaşlar ya da durur. Enerji üretimi ve onarım gibi işlemler aksar. Hücre zayıf düşer."},{"t":"Sonuç","a":"Hücre ölümü","d":"Süreklilik kazanan bu sorunlar zinciri sonunda hücreyi yaşayamaz hâle getirir. Protein eksikliği yaşamsal işlevleri çökertir. Böylece hücre ölür."}],"ans":"Çekirdekçik bozulunca ribozom üretimi düşer, protein sentezi azalır, enzim eksikliğiyle hücre içi tepkimeler durur ve sonunda hücre ölür."},{"q":"Çekirdek porlarından geçişin yönlü (içeri veya dışarı) olması hücre için neden gereklidir?","steps":[{"t":"İçeri yönlü geçiş","a":"Proteinler girer","d":"Çekirdekte iş gören bazı proteinler sitoplazmada üretilir. Bunların çekirdek içine taşınması gerekir. Porlar bu proteinleri içeri alır."},{"t":"Dışarı yönlü geçiş","a":"RNA çıkar","d":"Çekirdekte üretilen RNA ve ribozom parçaları sitoplazmada görev yapar. Bunların dışarı çıkması gerekir. Porlar bu maddeleri dışarı verir."},{"t":"Yönlü denetim","a":"Karışıklık önlenir","d":"Geçişin yönlü olması, doğru maddenin doğru yöne taşınmasını sağlar. Eğer geçiş rastgele olsaydı maddeler yanlış yerde birikirdi. Yönlü denetim bu karışıklığı önler."},{"t":"Sonuç","a":"Düzenli işleyiş","d":"Yönlü geçiş, çekirdek ve sitoplazma arasındaki iş bölümünü düzenli kılar. Her madde gerektiği yere ulaşır. Böylece hücre işlevleri uyum içinde yürür."}],"ans":"Yönlü geçiş, çekirdeğe gereken proteinlerin içeri, RNA ve ribozom parçalarının dışarı taşınmasını düzenleyerek maddelerin doğru yerde olmasını ve hücrenin uyumlu işleyişini sağlar."},{"q":"Çok çekirdekli çizgili kas hücrelerinin oluşumu, çekirdek-sitoplazma oranı kavramıyla nasıl açıklanır?","steps":[{"t":"Çekirdek-sitoplazma oranı","a":"Dengeli olmalı","d":"Bir çekirdek, belirli bir sitoplazma hacmini yönetebilir. Sitoplazma çok büyürse tek çekirdek yetmez. Bu dengeye çekirdek-sitoplazma oranı denir."},{"t":"Kas hücresinin büyüklüğü","a":"Çok büyük","d":"Çizgili kas hücreleri uzun ve çok büyük hacimli hücrelerdir. Tek bir çekirdek bu kadar büyük sitoplazmayı yönetmekte yetersiz kalır. Bu nedenle daha çok çekirdek gerekir."},{"t":"Çok çekirdeklilik","a":"Yönetim paylaşılır","d":"Kas hücreleri birden çok çekirdek bularak büyük hacmi paylaşarak yönetir. Her çekirdek çevresindeki bölgeden sorumlu olur. Böylece büyük hücre düzgün yönetilir."},{"t":"Sonuç","a":"Oran korunur","d":"Çok çekirdeklilik sayesinde çekirdek-sitoplazma oranı dengeye getirilir. Büyük hücre yeterli yönetim kapasitesine kavuşur. Bu nedenle çizgili kas hücreleri çok çekirdeklidir."}],"ans":"Çizgili kas hücreleri çok büyük olduğundan tek çekirdek yetersiz kalır; birden çok çekirdek alarak çekirdek-sitoplazma oranını dengeler ve büyük hacmi düzgün yönetir."},{"q":"Çekirdek zarının çift katlı olması, prokaryottan ökaryota geçiş açısından endosimbiyozla nasıl ilişkilendirilebilir?","steps":[{"t":"Çift zar gözlemi","a":"İki katman","d":"Çekirdek zarı iki katmanlı bir yapıdadır. Bu yapı tek katlı basit bir zardan farklıdır. Çift katmanlılık dikkat çekici bir özelliktir."},{"t":"Endosimbiyozla bağlantı","a":"Zar katlanması","d":"Bir görüşe göre çekirdek zarı, hücre zarının içeri doğru katlanmasıyla oluşmuş olabilir. İçeri katlanan zar DNA'yı çevreleyerek çift katlı bir yapı oluşturur. Bu, ökaryot hücrenin gelişim sürecinin bir parçası sayılır."},{"t":"Bölmelenmenin önemi","a":"DNA korunur","d":"Çift zarla çevrelenen DNA artık sitoplazmadan ayrılmış olur. Bu bölmelenme ökaryotun temel kazanımıdır. Böylece daha karmaşık denetim mümkün hâle gelir."},{"t":"Sonuç","a":"Karmaşıklığa geçiş","d":"Çift katlı çekirdek zarı, basit prokaryottan karmaşık ökaryota geçişin bir işaretidir. Zar katlanması ve bölmelenme bu geçişi açıklar. Böylece çekirdek, ökaryot karmaşıklığının temel taşı olur."}],"ans":"Çift katlı çekirdek zarı, hücre zarının içeri katlanarak DNA'yı çevrelemesiyle açıklanabilir; bu bölmelenme prokaryottan karmaşık ökaryota geçişin temel adımıdır."},{"q":"Bir hücrede çekirdek zarı sağlam ama porları tıkalı olsaydı protein sentezi nasıl etkilenirdi?","steps":[{"t":"Tıkalı porlar","a":"Geçiş durur","d":"Porlar tıkalıysa çekirdek ile sitoplazma arasında madde geçişi durur. RNA dışarı çıkamaz, proteinler içeri giremez. Çekirdek yalıtılmış hâle gelir."},{"t":"mRNA hapsolur","a":"Sitoplazmaya çıkamaz","d":"Çekirdekte üretilen mRNA porlardan geçemediği için sitoplazmaya ulaşamaz. Ribozomlar bu bilgiyi alamaz. Protein üretiminin temel girdisi eksik kalır."},{"t":"Ribozom eksikliği","a":"Yeni ribozom çıkamaz","d":"Çekirdekçikte üretilen ribozom parçaları da dışarı çıkamaz. Sitoplazmada yeni ribozom oluşamaz. Bu da protein üretim kapasitesini düşürür."},{"t":"Sonuç","a":"Sentez durur","d":"mRNA ve ribozom çıkamadığı için protein sentezi büyük ölçüde durur. Çekirdek sağlam olsa bile iletişim koptuğu için işlevsiz kalır. Sonuçta hücre yaşamsal proteinlerini üretemez."}],"ans":"Porlar tıkalı olsaydı mRNA ve ribozom parçaları çekirdekten çıkamaz, ribozomlar bilgi alamaz ve protein sentezi büyük ölçüde durarak hücre işlevsiz kalırdı."},{"q":"Kromatinin ökromatin ve heterokromatin olarak ikiye ayrılması hücreye nasıl bir esneklik sağlar?","steps":[{"t":"Ökromatin","a":"Gevşek, etkin","d":"Ökromatin gevşek paketlenmiş kromatin bölgesidir. Bu bölgedeki genler okunmaya açıktır. Yani etkin genleri barındırır."},{"t":"Heterokromatin","a":"Sıkı, etkisiz","d":"Heterokromatin sıkı paketlenmiş kromatin bölgesidir. Bu bölgedeki genler okunamaz hâldedir. Yani etkisiz, sessiz genleri içerir."},{"t":"Sağladığı esneklik","a":"Gen seçimi","d":"Hücre, genleri ökromatin ya da heterokromatin durumuna getirerek hangi genleri kullanacağını seçer. İhtiyaca göre bir gen açılıp kapatılabilir. Bu seçim hücre tipine ve duruma göre değişir."},{"t":"Sonuç","a":"Uyum yeteneği","d":"Bu iki kromatin durumu hücreye gen etkinliğini ayarlama esnekliği verir. Aynı DNA'dan farklı işlevler elde edilir. Böylece hücre değişen koşullara uyum sağlar."}],"ans":"Ökromatin (gevşek, etkin) ve heterokromatin (sıkı, etkisiz) ayrımı hücreye genleri ihtiyaca göre açıp kapatma esnekliği verir; böylece aynı DNA'dan farklı işlevler elde edilip değişen koşullara uyum sağlanır."},{"q":"Çekirdek, hücre içi haberleşmede neden hem alıcı hem komut veren konumdadır?","steps":[{"t":"Komut veren rol","a":"DNA'dan emir","d":"Çekirdek, DNA'daki bilgiyi kullanarak hangi proteinlerin üretileceğini belirler. Bu, hücreye verilen komutlardır. Yani çekirdek komutların kaynağıdır."},{"t":"Alıcı rol","a":"Sinyalleri alır","d":"Sitoplazmadan ve dış ortamdan gelen sinyaller porlar yoluyla çekirdeğe ulaşır. Bu sinyaller hücrenin durumunu çekirdeğe bildirir. Çekirdek bu bilgileri değerlendirir."},{"t":"İki yönlü iletişim","a":"Al ve yönet","d":"Çekirdek gelen sinyalleri alıp buna göre yeni komutlar üretir. Yani önce dinler, sonra yönlendirir. Bu iki yönlü işleyiş hücreyi koşullara uyumlu kılar."},{"t":"Sonuç","a":"Çift rollü merkez","d":"Çekirdek hem dış ve iç sinyalleri alan hem de komut üreten çift rollü bir merkezdir. Bu sayede hücre ihtiyaca uygun tepki verir. Böylece hücre içi haberleşmenin kalbi olur."}],"ans":"Çekirdek, porlardan gelen sinyalleri alıp değerlendirir ve DNA'ya göre yeni komutlar üretir; bu iki yönlü işleyiş onu hem alıcı hem komut veren merkez yapar."},{"q":"Olgun memeli alyuvarının çekirdeksiz olması, görev özelleşmesi ile yaşam süresi arasındaki ilişkiyi nasıl gösterir?","steps":[{"t":"Çekirdeksizlik","a":"Yer açar","d":"Olgun memeli alyuvarı çekirdeğini atar. Böylece içinde oksijen taşıyıcı madde için daha çok yer kalır. Bu, oksijen taşıma görevini güçlendirir."},{"t":"Görev özelleşmesi","a":"Tek işe odak","d":"Çekirdeksiz alyuvar yalnızca oksijen taşıma görevine özelleşir. Bölünme ve onarım gibi işleri yapamaz. Tek bir işe odaklanır."},{"t":"Yaşam süresine etkisi","a":"Kısalır","d":"Çekirdek olmadığı için alyuvar yeni protein üretemez ve kendini onaramaz. Yıpranan yapılarını yenileyemez. Bu nedenle yaşam süresi sınırlıdır, yaklaşık birkaç aydır."},{"t":"Sonuç","a":"Verim-süre dengesi","d":"Çekirdeksizlik yüksek oksijen taşıma verimi sağlar ama yaşam süresini kısaltır. Yani hücre, görevde uzmanlaşma karşılığında ömründen feda eder. Bu, özelleşme ile yaşam süresi arasındaki dengeyi gösterir."}],"ans":"Çekirdeksiz alyuvar oksijen taşımada uzmanlaşır ama kendini onaramadığından kısa ömürlüdür; bu durum görev özelleşmesinin yaşam süresinden ödün vererek elde edildiğini gösterir."},{"q":"Bir virüsün çekirdeğe girip DNA'ya yerleşmesi, çekirdeğin yönetim merkezi oluşunu nasıl istismar eder?","steps":[{"t":"Çekirdeğin gücü","a":"Üretimi yönetir","d":"Çekirdek, DNA aracılığıyla hücrenin tüm üretim faaliyetlerini yönetir. Hangi proteinin üretileceğini belirler. Yani üretim emirleri buradan çıkar."},{"t":"Virüsün hedefi","a":"DNA'ya yerleşir","d":"Bazı virüsler kendi genetik bilgisini hücrenin DNA'sına ekler. Böylece çekirdeğin komut sistemine sızar. Hücrenin yönetim mekanizmasını ele geçirir."},{"t":"İstismar mekanizması","a":"Kendini ürettirir","d":"Virüs, çekirdeğin üretim gücünü kendi kopyalarını üretmek için kullanır. Hücre, kendi ihtiyaçları yerine virüs parçalarını üretmeye başlar. Böylece çekirdeğin yönetim gücü virüse hizmet eder."},{"t":"Sonuç","a":"Hücre virüs üretir","d":"Çekirdek artık hücre değil virüs için çalışır hâle gelir. Üretilen virüsler yeni hücreleri de etkiler. Yani virüs, çekirdeğin yönetim merkezi oluşunu kendi yararına istismar eder."}],"ans":"Virüs kendi genetik bilgisini hücre DNA'sına ekleyerek çekirdeğin üretim yönetimini ele geçirir ve hücreyi kendi kopyalarını üretmeye zorlar; böylece çekirdeğin yönetim gücünü istismar eder."},{"q":"Çekirdek zarı, ribozom ve endoplazmik retikulum birlikte düşünüldüğünde bir proteinin üretilip salgılanma yolu nasıl izlenir?","steps":[{"t":"Bilgi çekirdekte","a":"mRNA üretimi","d":"Önce çekirdekte DNA'dan proteinin bilgisini taşıyan mRNA üretilir. Bu mRNA işlenip olgunlaştırılır. Ardından çekirdek porlarından sitoplazmaya geçer."},{"t":"Ribozomda üretim","a":"ER'ye bağlı ribozom","d":"mRNA, endoplazmik retikuluma bağlı ribozoma ulaşır. Ribozom bu bilgiye göre proteini üretir. Üretilen protein doğrudan endoplazmik retikulumun içine girer."},{"t":"ER'de işlenme","a":"Protein olgunlaşır","d":"Endoplazmik retikulumda protein katlanır ve düzenlenir. Gerekli düzeltmeler burada yapılır. Sonra kesecikler hâlinde sonraki aşamaya gönderilir."},{"t":"Sonuç","a":"Salgılanma yolu","d":"Çekirdek bilgiyi sağlar, ribozom üretir, endoplazmik retikulum işler ve protein sonunda hücreden salgılanır. Bu yapıların hepsi zar bağlantılarıyla uyum içinde çalışır. Böylece bir protein üretilip dışarı verilir."}],"ans":"Çekirdekte mRNA üretilir, porlardan çıkıp ER'ye bağlı ribozomda protein sentezlenir, ER'de olgunlaştırılır ve kesecikle taşınıp salgılanır; bu yapılar zar bağlantılarıyla uyumla çalışır."}]}}};
